package adminapi

import (
	"context"
	"crypto/subtle"
	"fmt"
	"net/http"
	"sync"
	"time"

	"github.com/gin-gonic/gin"
	"k8s.io/klog/v2"

	"github.com/anomalyco/agentcube/pkg/store"
)

const (
	DefaultPort              = 8081
	DefaultReadTimeout       = 30 * time.Second
	DefaultWriteTimeout      = 30 * time.Second
	DefaultReadHeaderTimeout = 10 * time.Second
)

type Config struct {
	Port          int
	AdminToken    string
	ReadTimeout   time.Duration
	WriteTimeout  time.Duration
	EnableMetrics bool
}

type Server struct {
	router      *gin.Engine
	config      *Config
	store       store.Store
	server      *http.Server
	metrics     *Metrics
	startTime   time.Time
	requestMu   sync.RWMutex
	requests    int64
	connections int64
}

type Metrics struct {
	TotalRequests   int64
	ActiveSessions  int64
	ExpiredSessions int64
	Errors          int64
}

type SystemStatus struct {
	Status        string    `json:"status"`
	Uptime        string    `json:"uptime"`
	TotalRequests int64     `json:"totalRequests"`
	ActiveConns   int64     `json:"activeConnections"`
	Timestamp     time.Time `json:"timestamp"`
}

type SessionStats struct {
	Total     int64 `json:"total"`
	Active    int64 `json:"active"`
	Expired   int64 `json:"expired"`
	CleanedUp int64 `json:"cleanedUp"`
}

func NewConfig() *Config {
	return &Config{
		Port:          DefaultPort,
		EnableMetrics: true,
		ReadTimeout:   DefaultReadTimeout,
		WriteTimeout:  DefaultWriteTimeout,
	}
}

func (c *Config) Validate() error {
	if c.Port <= 0 || c.Port > 65535 {
		return fmt.Errorf("invalid port: %d", c.Port)
	}
	if c.AdminToken == "" {
		return fmt.Errorf("admin token is required")
	}
	return nil
}

func NewServer(cfg *Config, store store.Store) *Server {
	gin.SetMode(gin.ReleaseMode)
	router := gin.New()

	s := &Server{
		router:    router,
		config:    cfg,
		store:     store,
		metrics:   &Metrics{},
		startTime: time.Now(),
	}

	s.setupRoutes()
	return s
}

func (s *Server) setupRoutes() {
	s.router.Use(gin.Recovery())
	s.router.Use(s.loggingMiddleware())
	s.router.Use(s.adminAuthMiddleware())

	s.router.GET("/health", s.healthHandler)

	admin := s.router.Group("/admin")
	{
		admin.GET("/status", s.statusHandler)
		admin.GET("/sessions", s.listSessionsHandler)
		admin.GET("/sessions/:sessionId", s.getSessionHandler)
		admin.DELETE("/sessions/:sessionId", s.deleteSessionHandler)
		admin.POST("/sessions/cleanup", s.cleanupSessionsHandler)
		admin.GET("/stats", s.statsHandler)
		admin.GET("/metrics", s.metricsHandler)
		admin.POST("/config/reload", s.configReloadHandler)
	}
}

func (s *Server) loggingMiddleware() gin.HandlerFunc {
	return func(c *gin.Context) {
		start := time.Now()
		path := c.Request.URL.Path

		c.Next()

		latency := time.Since(start)
		status := c.Writer.Status()

		klog.V(2).InfoS("Admin API request",
			"method", c.Request.Method,
			"path", path,
			"status", status,
			"latency", latency.String(),
			"clientIP", c.ClientIP(),
		)
	}
}

func (s *Server) adminAuthMiddleware() gin.HandlerFunc {
	return func(c *gin.Context) {
		authHeader := c.GetHeader("Authorization")
		if authHeader == "" {
			c.JSON(http.StatusUnauthorized, gin.H{"error": "missing authorization header"})
			c.Abort()
			return
		}

		expectedAuth := "Bearer " + s.config.AdminToken
		if subtle.ConstantTimeCompare([]byte(authHeader), []byte(expectedAuth)) != 1 {
			c.JSON(http.StatusForbidden, gin.H{"error": "invalid admin token"})
			c.Abort()
			return
		}

		c.Set("admin", true)
		c.Next()
	}
}

func (s *Server) healthHandler(c *gin.Context) {
	c.JSON(http.StatusOK, gin.H{
		"status":  "ok",
		"service": "admin-api",
	})
}

func (s *Server) statusHandler(c *gin.Context) {
	s.requestMu.RLock()
	requests := s.requests
	s.requestMu.RUnlock()

	c.JSON(http.StatusOK, SystemStatus{
		Status:        "running",
		Uptime:        time.Since(s.startTime).String(),
		TotalRequests: requests,
		ActiveConns:   s.connections,
		Timestamp:     time.Now(),
	})
}

func (s *Server) listSessionsHandler(c *gin.Context) {
	ctx := c.Request.Context()

	expired, err := s.store.ListExpiredSandboxes(ctx, time.Now().Add(24*time.Hour), 1000)
	if err != nil {
		klog.ErrorS(err, "Failed to list sessions")
		c.JSON(http.StatusInternalServerError, gin.H{"error": "failed to list sessions", "detail": err.Error()})
		return
	}

	c.JSON(http.StatusOK, gin.H{
		"sessions": expired,
		"count":    len(expired),
	})
}

func (s *Server) getSessionHandler(c *gin.Context) {
	sessionID := c.Param("sessionId")
	if sessionID == "" {
		c.JSON(http.StatusBadRequest, gin.H{"error": "sessionId is required"})
		return
	}

	ctx := c.Request.Context()
	sandbox, err := s.store.GetSandboxBySessionID(ctx, sessionID)
	if err != nil {
		if err == store.ErrSessionNotFound {
			c.JSON(http.StatusNotFound, gin.H{"error": "session not found", "sessionId": sessionID})
			return
		}
		c.JSON(http.StatusInternalServerError, gin.H{"error": "failed to get session", "detail": err.Error()})
		return
	}

	c.JSON(http.StatusOK, sandbox)
}

func (s *Server) deleteSessionHandler(c *gin.Context) {
	sessionID := c.Param("sessionId")
	if sessionID == "" {
		c.JSON(http.StatusBadRequest, gin.H{"error": "sessionId is required"})
		return
	}

	ctx := c.Request.Context()
	if err := s.store.DeleteSandboxBySessionID(ctx, sessionID); err != nil {
		if err == store.ErrSessionNotFound {
			c.JSON(http.StatusNotFound, gin.H{"error": "session not found", "sessionId": sessionID})
			return
		}
		c.JSON(http.StatusInternalServerError, gin.H{"error": "failed to delete session", "detail": err.Error()})
		return
	}

	klog.InfoS("Admin deleted session", "sessionId", sessionID)
	c.JSON(http.StatusOK, gin.H{"status": "deleted", "sessionId": sessionID})
}

func (s *Server) cleanupSessionsHandler(c *gin.Context) {
	ctx := c.Request.Context()
	now := time.Now()

	expired, err := s.store.ListExpiredSandboxes(ctx, now, 100)
	if err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": "failed to list expired sessions", "detail": err.Error()})
		return
	}

	cleaned := 0
	for _, sandbox := range expired {
		if err := s.store.DeleteSandboxBySessionID(ctx, sandbox.SessionID); err != nil {
			klog.ErrorS(err, "Failed to delete expired session", "sessionId", sandbox.SessionID)
			continue
		}
		cleaned++
	}

	klog.InfoS("Admin cleanup completed", "cleaned", cleaned, "expired", len(expired))
	c.JSON(http.StatusOK, gin.H{
		"status":  "completed",
		"cleaned": cleaned,
		"total":   len(expired),
	})
}

func (s *Server) statsHandler(c *gin.Context) {
	s.requestMu.RLock()
	metrics := *s.metrics
	s.requestMu.RUnlock()

	c.JSON(http.StatusOK, gin.H{
		"metrics": metrics,
		"uptime":  time.Since(s.startTime).String(),
	})
}

func (s *Server) metricsHandler(c *gin.Context) {
	c.JSON(http.StatusOK, s.metrics)
}

func (s *Server) configReloadHandler(c *gin.Context) {
	klog.InfoS("Admin config reload requested")
	c.JSON(http.StatusOK, gin.H{
		"status":  "accepted",
		"message": "config reload initiated",
	})
}

func (s *Server) Run(ctx context.Context) error {
	addr := fmt.Sprintf(":%d", s.config.Port)

	s.server = &http.Server{
		Addr:              addr,
		Handler:           s.router,
		ReadTimeout:       s.config.ReadTimeout,
		WriteTimeout:      s.config.WriteTimeout,
		ReadHeaderTimeout: DefaultReadHeaderTimeout,
	}

	errCh := make(chan error, 1)

	go func() {
		klog.InfoS("Starting Admin API server", "addr", addr)

		if err := s.server.ListenAndServe(); err != nil && err != http.ErrServerClosed {
			errCh <- err
		}
	}()

	select {
	case err := <-errCh:
		return err
	case <-ctx.Done():
		return s.Shutdown(context.Background())
	}
}

func (s *Server) Shutdown(ctx context.Context) error {
	if s.server != nil {
		klog.InfoS("Shutting down Admin API server")
		return s.server.Shutdown(ctx)
	}
	return nil
}

func (s *Server) IncrementRequests() {
	s.requestMu.Lock()
	s.requests++
	s.metrics.TotalRequests++
	s.requestMu.Unlock()
}

func (s *Server) RecordError() {
	s.requestMu.Lock()
	s.metrics.Errors++
	s.requestMu.Unlock()
}

package adminapi

import (
	"context"
	"encoding/json"
	"net/http"
	"net/http/httptest"
	"testing"
	"time"

	"github.com/gin-gonic/gin"
	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"

	"github.com/anomalyco/agentcube/pkg/common/types"
)

type mockStore struct {
	sessions map[string]*types.SandboxInfo
}

func newMockStore() *mockStore {
	return &mockStore{
		sessions: make(map[string]*types.SandboxInfo),
	}
}

func (m *mockStore) Ping(ctx context.Context) error {
	return nil
}

func (m *mockStore) GetSandboxBySessionID(ctx context.Context, sessionID string) (*types.SandboxInfo, error) {
	if s, ok := m.sessions[sessionID]; ok {
		return s, nil
	}
	return nil, ErrSessionNotFound
}

func (m *mockStore) StoreSandbox(ctx context.Context, sandbox *types.SandboxInfo) error {
	m.sessions[sandbox.SessionID] = sandbox
	return nil
}

func (m *mockStore) UpdateSandbox(ctx context.Context, sandbox *types.SandboxInfo) error {
	m.sessions[sandbox.SessionID] = sandbox
	return nil
}

func (m *mockStore) DeleteSandboxBySessionID(ctx context.Context, sessionID string) error {
	if _, ok := m.sessions[sessionID]; !ok {
		return ErrSessionNotFound
	}
	delete(m.sessions, sessionID)
	return nil
}

func (m *mockStore) ListExpiredSandboxes(ctx context.Context, before time.Time, limit int64) ([]*types.SandboxInfo, error) {
	var result []*types.SandboxInfo
	for _, s := range m.sessions {
		if s.ExpiresAt.Before(before) {
			result = append(result, s)
		}
	}
	return result, nil
}

func (m *mockStore) ListInactiveSandboxes(ctx context.Context, before time.Time, limit int64) ([]*types.SandboxInfo, error) {
	var result []*types.SandboxInfo
	for _, s := range m.sessions {
		if s.LastActivityAt.Before(before) {
			result = append(result, s)
		}
	}
	return result, nil
}

func (m *mockStore) UpdateSessionLastActivity(ctx context.Context, sessionID string, at time.Time) error {
	if s, ok := m.sessions[sessionID]; ok {
		s.LastActivityAt = at
		return nil
	}
	return ErrSessionNotFound
}

func (m *mockStore) Close() error {
	return nil
}

var ErrSessionNotFound = types.ErrSessionNotFound

func init() {
	gin.SetMode(gin.TestMode)
}

func TestNewConfig(t *testing.T) {
	cfg := NewConfig()
	assert.Equal(t, DefaultPort, cfg.Port)
	assert.True(t, cfg.EnableMetrics)
	assert.Equal(t, DefaultReadTimeout, cfg.ReadTimeout)
	assert.Equal(t, DefaultWriteTimeout, cfg.WriteTimeout)
}

func TestConfigValidate(t *testing.T) {
	tests := []struct {
		name    string
		config  *Config
		wantErr bool
		errMsg  string
	}{
		{
			name: "valid config",
			config: &Config{
				Port:       8081,
				AdminToken: "test-token",
			},
			wantErr: false,
		},
		{
			name: "invalid port negative",
			config: &Config{
				Port:       -1,
				AdminToken: "test-token",
			},
			wantErr: true,
			errMsg:  "invalid port",
		},
		{
			name: "invalid port too high",
			config: &Config{
				Port:       70000,
				AdminToken: "test-token",
			},
			wantErr: true,
			errMsg:  "invalid port",
		},
		{
			name: "missing admin token",
			config: &Config{
				Port:       8081,
				AdminToken: "",
			},
			wantErr: true,
			errMsg:  "admin token is required",
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			err := tt.config.Validate()
			if tt.wantErr {
				require.Error(t, err)
				assert.Contains(t, err.Error(), tt.errMsg)
			} else {
				require.NoError(t, err)
			}
		})
	}
}

func TestNewServer(t *testing.T) {
	cfg := &Config{
		Port:       8081,
		AdminToken: "test-admin-token",
	}
	store := newMockStore()

	server := NewServer(cfg, store)
	require.NotNil(t, server)
	assert.NotNil(t, server.router)
	assert.NotNil(t, server.config)
