func TestGetSessionHandler(t *testing.T) {
	cfg := &Config{
		Port:       8081,
		AdminToken: "test-admin-token",
	}
	store := newMockStore()

	session := &types.SandboxInfo{
		SessionID: "test-session-1",
		Name:      "test-sandbox",
		Namespace: "default",
		Kind:      "AgentRuntime",
		CreatedAt: time.Now(),
		ExpiresAt: time.Now().Add(24 * time.Hour),
	}
	store.sessions[session.SessionID] = session

	server := NewServer(cfg, store)

	t.Run("existing session", func(t *testing.T) {
		w := httptest.NewRecorder()
		req, _ := http.NewRequest("GET", "/admin/sessions/test-session-1", nil)
		req.Header.Set("Authorization", "Bearer test-admin-token")
		server.router.ServeHTTP(w, req)

		assert.Equal(t, http.StatusOK, w.Code)

		var resp types.SandboxInfo
		err := json.Unmarshal(w.Body.Bytes(), &resp)
		require.NoError(t, err)
		assert.Equal(t, "test-session-1", resp.SessionID)
		assert.Equal(t, "test-sandbox", resp.Name)
	})

	t.Run("non-existing session", func(t *testing.T) {
		w := httptest.NewRecorder()
		req, _ := http.NewRequest("GET", "/admin/sessions/non-existent", nil)
		req.Header.Set("Authorization", "Bearer test-admin-token")
		server.router.ServeHTTP(w, req)

		assert.Equal(t, http.StatusNotFound, w.Code)
	})
}

func TestDeleteSessionHandler(t *testing.T) {
	cfg := &Config{
		Port:       8081,
		AdminToken: "test-admin-token",
	}
	store := newMockStore()

	session := &types.SandboxInfo{
		SessionID: "test-session-1",
		Name:      "test-sandbox",
		Namespace: "default",
		Kind:      "AgentRuntime",
		CreatedAt: time.Now(),
		ExpiresAt: time.Now().Add(24 * time.Hour),
	}
	store.sessions[session.SessionID] = session

	server := NewServer(cfg, store)

	t.Run("delete existing session", func(t *testing.T) {
		w := httptest.NewRecorder()
