func TestCleanupSessionsHandler(t *testing.T) {
	cfg := &Config{
		Port:       8081,
		AdminToken: "test-admin-token",
	}
	store := newMockStore()

	now := time.Now()

	expiredSession := &types.SandboxInfo{
		SessionID: "expired-session",
		Name:      "expired-sandbox",
		Namespace: "default",
		Kind:      "AgentRuntime",
		CreatedAt: now.Add(-2 * time.Hour),
		ExpiresAt: now.Add(-1 * time.Hour),
	}
	store.sessions[expiredSession.SessionID] = expiredSession

	activeSession := &types.SandboxInfo{
		SessionID: "active-session",
		Name:      "active-sandbox",
		Namespace: "default",
		Kind:      "AgentRuntime",
		CreatedAt: now,
		ExpiresAt: now.Add(24 * time.Hour),
	}
	store.sessions[activeSession.SessionID] = activeSession

	server := NewServer(cfg, store)

