package metrics

import (
	"context"
	"fmt"
	"net/http"
	"sync"
	"sync/atomic"
	"time"

	"github.com/gin-gonic/gin"
	"github.com/prometheus/client_golang/prometheus"
	"github.com/prometheus/client_golang/prometheus/promhttp"
	"k8s.io/klog/v2"

	"github.com/anomalyco/agentcube/pkg/store"
)

const (
	DefaultPort              = 9090
	DefaultReadTimeout       = 30 * time.Second
	DefaultWriteTimeout      = 30 * time.Second
	DefaultReadHeaderTimeout = 10 * time.Second
	Namespace                = "agentcube"
)

type Config struct {
	Port         int
	ReadTimeout  time.Duration
	WriteTimeout time.Duration
	Registry     *prometheus.Registry
}

type Server struct {
	router    *gin.Engine
	config    *Config
	store     store.Store
	server    *http.Server
	registry  *prometheus.Registry
	collectors *Collectors
}

type Collectors struct {
	RequestsTotal     *prometheus.CounterVec
	RequestDuration   *prometheus.HistogramVec
	ActiveSessions    prometheus.Gauge
	ExpiredSessions   prometheus.Gauge
	SessionCreated    *prometheus.CounterVec
	SessionDeleted    *prometheus.CounterVec
	ErrorsTotal       *prometheus.CounterVec
	ProxyRequests     *prometheus.CounterVec
	ProxyLatency      *prometheus.HistogramVec
	CacheHits         prometheus.Counter
	CacheMisses       prometheus.Counter
	DatabaseLatency   *prometheus.HistogramVec
	ActiveConnections prometheus.Gauge
}

func NewConfig() *Config {
	return &Config{
		Port:         DefaultPort,
		ReadTimeout:  DefaultReadTimeout,
		WriteTimeout: DefaultWriteTimeout,
	}
}

func (c *Config) Validate() error {
	if c.Port <= 0 || c.Port > 65535 {
		return fmt.Errorf("invalid port: %d", c.Port)
	}
	return nil
}

func NewCollectors() *Collectors {
	return &Collectors{
		RequestsTotal: prometheus.NewCounterVec(
			prometheus.CounterOpts{
				Namespace: Namespace,
				Name:      "http_requests_total",
				Help:      "Total number of HTTP requests",
			},
			[]string{"method", "path", "status"},
		),
		RequestDuration: prometheus.NewHistogramVec(
			prometheus.HistogramOpts{
				Namespace: Namespace,
				Name:      "http_request_duration_seconds",
				Help:      "HTTP request duration in seconds",
				Buckets:   prometheus.DefBuckets,
			},
			[]string{"method", "path"},
		),
		ActiveSessions: prometheus.NewGauge(
			prometheus.GaugeOpts{
				Namespace: Namespace,
				Name:      "active_sessions_total",
				Help:      "Number of active sessions",
			},
		),
		ExpiredSessions: prometheus.NewGauge(
			prometheus.GaugeOpts{
				Namespace: Namespace,
				Name:      "expired_sessions_total",
				Help:      "Number of expired sessions",
			},
		),
		SessionCreated: prometheus.NewCounterVec(
			prometheus.CounterOpts{
				Namespace: Namespace,
				Name:      "sessions_created_total",
				Help:      "Total number of sessions created",
			},
			[]string{"kind"},
		),
		SessionDeleted: prometheus.NewCounterVec(
			prometheus.CounterOpts{
				Namespace: Namespace,
				Name:      "sessions_deleted_total",
				Help:      "Total number of sessions deleted",
			},
			[]string{"kind", "reason"},
		),
		ErrorsTotal: prometheus.NewCounterVec(
			prometheus.CounterOpts{
				Namespace: Namespace,
				Name:      "errors_total",
				Help:      "Total number of errors",
			},
			[]string{"component", "type"},
		),
		ProxyRequests: prometheus.NewCounterVec(
			prometheus.CounterOpts{
				Namespace: Namespace,
				Name:      "proxy_requests_total",
				Help:      "Total number of proxy requests",
			},
			[]string{"target", "status"},
		),
		ProxyLatency: prometheus.NewHistogramVec(
			prometheus.HistogramOpts{
				Namespace: Namespace,
				Name:      "proxy_latency_seconds",
				Help:      "Proxy request latency in seconds",
				Buckets:   prometheus.DefBuckets,
			},
			[]string{"target"},
		),
		CacheHits: prometheus.NewCounter(
			prometheus.CounterOpts{
				Namespace: Namespace,
				Name:      "cache_hits_total",
				Help:      "Total number of cache hits",
			},
		),
		CacheMisses: prometheus.NewCounter(
			prometheus.CounterOpts{
				Namespace: Namespace,
				Name:      "cache_misses_total",
				Help:      "Total number of cache misses",
			},
		),
		DatabaseLatency: prometheus.NewHistogramVec(
			prometheus.HistogramOpts{
				Namespace: Namespace,
				Name:      "database_latency_seconds",
				Help:      "Database operation latency in seconds",
				Buckets:   prometheus.DefBuckets,
			},
			[]string{"operation"},
		),
		ActiveConnections: prometheus.NewGauge(
			prometheus.GaugeOpts{
				Namespace: Namespace,
				Name:      "active_connections",
				Help:      "Number of active connections",
			},
		),
	}
}

func NewServer(cfg *Config, store store.Store) *Server {
	gin.SetMode(gin.ReleaseMode)
	router := gin.New()

	if cfg.Registry == nil {
		cfg.Registry = prometheus.NewRegistry()
	}

	collectors := NewCollectors()
	cfg.Registry.MustRegister(
		collectors.RequestsTotal,
		collectors.RequestDuration,
		collectors.ActiveSessions,
		collectors.ExpiredSessions,
		collectors.SessionCreated,
		collectors.SessionDeleted,
		collectors.ErrorsTotal,
		collectors.ProxyRequests,
		collectors.ProxyLatency,
		collectors.CacheHits,
		collectors.CacheMisses,
		collectors.DatabaseLatency,
		collectors.ActiveConnections,
	)

	s := &Server{
		router:     router,
		config:     cfg,
		store:      store,
		registry:   cfg.Registry,
		collectors: collectors,
	}

	s.setupRoutes()
	return s
}

func (s *Server) setupRoutes() {
	s.router.Use(gin.Recovery())
	s.router.Use(s.loggingMiddleware())

	s.router.GET("/health", s.healthHandler)
	s.router.GET("/metrics", gin.WrapH(promhttp.HandlerFor(s.registry, promhttp.HandlerOpts{})))
	s.router.GET("/ready", s.readyHandler)
}

func (s *Server) loggingMiddleware() gin.HandlerFunc {
	return func(c *gin.Context) {
		start := time.Now()
		path := c.Request.URL.Path

		c.Next()

		latency := time.Since(start)
		status := c.Writer.Status()

		s.collectors.RequestsTotal.WithLabelValues(
			c.Request.Method,
			path,
			fmt.Sprintf("%d", status),
		).Inc()

		s.collectors.RequestDuration.WithLabelValues(
			c.Request.Method,
			path,
		).Observe(latency.Seconds())

		klog.V(3).InfoS("Metrics request",
			"method", c.Request.Method,
			"path", path,
			"status", status,
			"latency", latency.String(),
		)
	}
}

func (s *Server) healthHandler(c *gin.Context) {
	c.JSON(http.StatusOK, gin.H{
		"status":  "ok",
		"service": "metrics-exporter",
	})
}

func (s *Server) readyHandler(c *gin.Context) {
	ctx := c.Request.Context()

	if s.store != nil {
		if err := s.store.Ping(ctx); err != nil {
			c.JSON(http.StatusServiceUnavailable, gin.H{
				"status": "not ready",
				"error":  "store unavailable",
			})
			return
		}
	}

	c.JSON(http.StatusOK, gin.H{
		"status": "ready",
	})
}

func (s *Server) RecordSessionCreated(kind string) {
	s.collectors.SessionCreated.WithLabelValues(kind).Inc()
}

func (s *Server) RecordSessionDeleted(kind, reason string) {
	s.collectors.SessionDeleted.WithLabelValues(kind, reason).Inc()
}

func (s *Server) RecordError(component, errType string) {
	s.collectors.ErrorsTotal.WithLabelValues(component, errType).Inc()
}

func (s *Server) RecordProxyRequest(target, status string, latency time.Duration) {
	s.collectors.ProxyRequests.WithLabelValues(target, status).Inc()
	s.collectors.ProxyLatency.WithLabelValues(target).Observe(latency.Seconds())
}

func (s *Server) RecordCacheHit() {
	s.collectors.CacheHits.Inc()
}

func (s *Server) RecordCacheMiss() {
	s.collectors.CacheMisses.Inc()
}

func (s *Server) RecordDatabaseLatency(operation string, latency time.Duration) {
	s.collectors.DatabaseLatency.WithLabelValues(operation).Observe(latency.Seconds())
}

func (s *Server) SetActiveSessions(count int64) {
	s.collectors.ActiveSessions.Set(float64(count))
}

func (s *Server) SetExpiredSessions(count int64) {
	s.collectors.ExpiredSessions.Set(float64(count))
}

func (s *Server) SetActiveConnections(count int64) {
	s.collectors.ActiveConnections.Set(float64(count))
}

func (s *Server) UpdateSessionMetrics(ctx context.Context) error {
	if s.store == nil {
		return nil
	}

	now := time.Now()

	active, err := s.store.ListInactiveSandboxes(ctx, now, 10000)
	if err != nil {
		klog.ErrorS(err, "Failed to list active sessions")
		return err
	}

	expired, err := s.store.ListExpiredSandboxes(ctx, now, 10000)
	if err != nil {
		klog.ErrorS(err, "Failed to list expired sessions")
		return err
	}

	s.SetActiveSessions(int64(len(active)))
	s.SetExpiredSessions(int64(len(expired)))

	return nil
}

func (s *Server) Run(ctx context.Context) error {
	addr := fmt.Sprintf(":%d", s.config.Port)

	s.server = &http.Server{
		Addr:              addr,
		Handler:           s.router,
		ReadTimeout:       s.config.ReadTimeout,
		WriteTimeout:      s.config.WriteTimeout,
		ReadHeaderTimeout: DefaultReadHeaderTimeout,
	}

	errCh := make(chan error, 1)

	go func() {
		klog.InfoS("Starting Metrics Exporter server", "addr", addr)

		if err := s.server.ListenAndServe(); err != nil && err != http.ErrServerClosed {
			errCh <- err
		}
	}()

	select {
	case err := <-errCh:
		return err
	case <-ctx.Done():
		return s.Shutdown(context.Background())
	}
}

func (s *Server) Shutdown(ctx context.Context) error {
	if s.server != nil {
		klog.InfoS("Shutting down Metrics Exporter server")
		return s.server.Shutdown(ctx)
	}
	return nil
}

func (s *Server) GetCollectors() *Collectors {
	return s.collectors
}

func (s *Server) GetRegistry() *prometheus.Registry {
	return s.registry
}

type MetricsSnapshot struct {
	Timestamp         time.Time `json:"timestamp"`
	RequestsTotal     int64     `json:"requestsTotal"`
	ActiveSessions    int64     `json:"activeSessions"`
	ExpiredSessions   int64     `json:"expiredSessions"`
	ErrorsTotal       int64     `json:"errorsTotal"`
	CacheHits         int64     `json:"cacheHits"`
	CacheMisses       int64     `json:"cacheMisses"`
	ActiveConnections int64     `json:"activeConnections"`
}

type atomicCounters struct {
	requestsTotal   int64
	errorsTotal     int64
	cacheHits       int64
	cacheMisses     int64
}

func (c *atomicCounters) IncRequests() {
	atomic.AddInt64(&c.requestsTotal, 1)
}

func (c *atomicCounters) IncErrors() {
	atomic.AddInt64(&c.errorsTotal, 1)
}

func (c *atomicCounters) IncCacheHits() {
	atomic.AddInt64(&c.cacheHits, 1)
}

func (c *atomicCounters) IncCacheMisses() {
	atomic.AddInt64(&c.cacheMisses, 1)
}

func (c *atomicCounters) GetRequests() int64 {
	return atomic.LoadInt64(&c.requestsTotal)
}

func (c *atomicCounters) GetErrors() int64 {
	return atomic.LoadInt64(&c.errorsTotal)
}

func (c *atomicCounters) GetCacheHits() int64 {
	return atomic.LoadInt64(&c.cacheHits)
}

func (c *atomicCounters) GetCacheMisses() int64 {
	return atomic.LoadInt64(&c.cacheMisses)
}

type MetricsRecorder struct {
	counters atomicCounters
	mu       sync.RWMutex
	gauges   map[string]float64
}

func NewMetricsRecorder() *MetricsRecorder {
	return &MetricsRecorder{
		gauges: make(map[string]float64),
	}
}

func (r *MetricsRecorder) IncRequests() {
	r.counters.IncRequests()
}

func (r *MetricsRecorder) IncErrors() {
	r.counters.IncErrors()
}

func (r *MetricsRecorder) IncCacheHits() {
	r.counters.IncCacheHits()
}

func (r *MetricsRecorder) IncCacheMisses() {
	r.counters.IncCacheMisses()
}

func (r *MetricsRecorder) SetGauge(name string, value float64) {
	r.mu.Lock()
	r.gauges[name] = value
	r.mu.Unlock()
}

func (r *MetricsRecorder) GetGauge(name string) float64 {
	r.mu.RLock()
	v := r.gauges[name]
	r.mu.RUnlock()
	return v
}

func (r *MetricsRecorder) Snapshot() MetricsSnapshot {
	r.mu.RLock()
	defer r.mu.RUnlock()

	return MetricsSnapshot{
		Timestamp:       time.Now(),
		RequestsTotal:   r.counters.GetRequests(),
		ErrorsTotal:     r.counters.GetErrors(),
		CacheHits:       r.counters.GetCacheHits(),
		CacheMisses:     r.counters.GetCacheMisses(),
		ActiveSessions:  int64(r.gauges["active_sessions"]),
		ExpiredSessions: int64(r.gauges["expired_sessions"]),
	}
}

