type mockMetricsStore struct {
	sessions map[string]*types.SandboxInfo
	pingErr  error
}

func newMockMetricsStore() *mockMetricsStore {
	return &mockMetricsStore{
		sessions: make(map[string]*types.SandboxInfo),
	}
}

func (m *mockMetricsStore) Ping(ctx context.Context) error {
	return m.pingErr
}

func (m *mockMetricsStore) GetSandboxBySessionID(ctx context.Context, sessionID string) (*types.SandboxInfo, error) {
	if s, ok := m.sessions[sessionID]; ok {
		return s, nil
	}
	return nil, types.ErrSessionNotFound
}

func (m *mockMetricsStore) StoreSandbox(ctx context.Context, sandbox *types.SandboxInfo) error {
	m.sessions[sandbox.SessionID] = sandbox
	return nil
}

func (m *mockMetricsStore) UpdateSandbox(ctx context.Context, sandbox *types.SandboxInfo) error {
	m.sessions[sandbox.SessionID] = sandbox
	return nil
}

func (m *mockMetricsStore) DeleteSandboxBySessionID(ctx context.Context, sessionID string) error {
	delete(m.sessions, sessionID)
	return nil
}

func (m *mockMetricsStore) ListExpiredSandboxes(ctx context.Context, before time.Time, limit int64) ([]*types.SandboxInfo, error) {
	var result []*types.SandboxInfo
	for _, s := range m.sessions {
		if s.ExpiresAt.Before(before) {
			result = append(result, s)
		}
	}
	return result, nil
}

func (m *mockMetricsStore) ListInactiveSandboxes(ctx context.Context, before time.Time, limit int64) ([]*types.SandboxInfo, error) {
	var result []*types.SandboxInfo
	for _, s := range m.sessions {
		if s.LastActivityAt.Before(before) {
			result = append(result, s)
		}
	}
	return result, nil
}

func (m *mockMetricsStore) UpdateSessionLastActivity(ctx context.Context, sessionID string, at time.Time) error {
	if s, ok := m.sessions[sessionID]; ok {
		s.LastActivityAt = at
	}
	return nil
}

func (m *mockMetricsStore) Close() error {
	return nil
}

