package webhook

import (
	"context"
	"crypto/hmac"
	"crypto/sha256"
	"encoding/hex"
	"encoding/json"
	"fmt"
	"net/http"
	"time"

	"github.com/gin-gonic/gin"
	"k8s.io/klog/v2"
)

const (
	DefaultPort              = 8082
	DefaultReadTimeout       = 30 * time.Second
	DefaultWriteTimeout      = 30 * time.Second
	DefaultReadHeaderTimeout = 10 * time.Second
	SignatureHeader          = "X-Signature-256"
	TimestampHeader          = "X-Timestamp"
	SignaturePrefix          = "sha256="
	MaxTimestampSkew         = 5 * time.Minute
)

type Config struct {
	Port           int
	Secret         string
	RequireSigning bool
	TimestampSkew  time.Duration
	ReadTimeout    time.Duration
	WriteTimeout   time.Duration
}

type Server struct {
	router    *gin.Engine
	config    *Config
	handlers  map[string]WebhookHandler
	server    *http.Server
	startTime time.Time
}

type WebhookHandler interface {
	Handle(ctx context.Context, event *WebhookEvent) (*WebhookResponse, error)
}

type WebhookEvent struct {
	ID        string                 `json:"id"`
	Type      string                 `json:"type"`
	Timestamp time.Time              `json:"timestamp"`
	Source    string                 `json:"source"`
	Payload   map[string]interface{} `json:"payload"`
	RawBody   []byte                 `json:"-"`
}

type WebhookResponse struct {
	Success   bool                   `json:"success"`
	Message   string                 `json:"message,omitempty"`
	Data      map[string]interface{} `json:"data,omitempty"`
	Retryable bool                   `json:"retryable,omitempty"`
}

type EventProcessor func(ctx context.Context, event *WebhookEvent) error

type HandlerFunc func(ctx context.Context, event *WebhookEvent) (*WebhookResponse, error)

func NewConfig() *Config {
	return &Config{
		Port:           DefaultPort,
		RequireSigning: true,
		TimestampSkew:  MaxTimestampSkew,
		ReadTimeout:    DefaultReadTimeout,
		WriteTimeout:   DefaultWriteTimeout,
	}
}

func (c *Config) Validate() error {
	if c.Port <= 0 || c.Port > 65535 {
		return fmt.Errorf("invalid port: %d", c.Port)
	}
	if c.RequireSigning && c.Secret == "" {
		return fmt.Errorf("secret is required when signing is enabled")
	}
	return nil
}

func NewServer(cfg *Config) *Server {
	gin.SetMode(gin.ReleaseMode)
	router := gin.New()

	s := &Server{
		router:    router,
		config:    cfg,
		handlers:  make(map[string]WebhookHandler),
		startTime: time.Now(),
	}

	s.setupRoutes()
	return s
}

func (s *Server) setupRoutes() {
	s.router.Use(gin.Recovery())
	s.router.Use(s.loggingMiddleware())

	s.router.GET("/health", s.healthHandler)

	webhooks := s.router.Group("/webhooks")
	{
		webhooks.POST("/:source", s.handleWebhook)
	}
}

func (s *Server) loggingMiddleware() gin.HandlerFunc {
	return func(c *gin.Context) {
		start := time.Now()
		path := c.Request.URL.Path

		c.Next()

		latency := time.Since(start)
		status := c.Writer.Status()

		klog.V(2).InfoS("Webhook request",
			"method", c.Request.Method,
			"path", path,
			"status", status,
			"latency", latency.String(),
			"clientIP", c.ClientIP(),
		)
	}
}

func (s *Server) healthHandler(c *gin.Context) {
	c.JSON(http.StatusOK, gin.H{
		"status":  "ok",
		"service": "webhook-handler",
		"uptime":  time.Since(s.startTime).String(),
	})
}

func (s *Server) signatureValidationMiddleware() gin.HandlerFunc {
	return func(c *gin.Context) {
		if !s.config.RequireSigning {
			c.Next()
			return
		}

		signature := c.GetHeader(SignatureHeader)
		if signature == "" {
			c.JSON(http.StatusUnauthorized, gin.H{"error": "missing signature header"})
			c.Abort()
			return
		}

		if len(signature) < len(SignaturePrefix) || signature[:len(SignaturePrefix)] != SignaturePrefix {
			c.JSON(http.StatusUnauthorized, gin.H{"error": "invalid signature format"})
			c.Abort()
			return
		}

		expectedSig := signature[len(SignaturePrefix):]

		var rawBody []byte
		if c.Request.Body != nil {
			_, err := c.Request.Body.Read(rawBody)
			if err != nil && err.Error() != "EOF" {
				c.JSON(http.StatusBadRequest, gin.H{"error": "failed to read body"})
				c.Abort()
				return
			}
		}

		mac := hmac.New(sha256.New, []byte(s.config.Secret))
		mac.Write(rawBody)
		computedSig := hex.EncodeToString(mac.Sum(nil))

		if !hmac.Equal([]byte(expectedSig), []byte(computedSig)) {
			c.JSON(http.StatusUnauthorized, gin.H{"error": "signature verification failed"})
			c.Abort()
			return
		}

		c.Next()
	}
}

func (s *Server) timestampValidationMiddleware() gin.HandlerFunc {
	return func(c *gin.Context) {
		if s.config.TimestampSkew == 0 {
			c.Next()
			return
		}

		timestampStr := c.GetHeader(TimestampHeader)
		if timestampStr == "" {
			c.Next()
			return
		}

		timestamp, err := time.Parse(time.RFC3339, timestampStr)
		if err != nil {
			c.JSON(http.StatusBadRequest, gin.H{"error": "invalid timestamp format"})
			c.Abort()
			return
		}

		now := time.Now()
		skew := now.Sub(timestamp)
		if skew < 0 {
			skew = -skew
		}

		if skew > s.config.TimestampSkew {
			c.JSON(http.StatusBadRequest, gin.H{"error": "timestamp skew too large"})
			c.Abort()
			return
		}

		c.Next()
	}
}

func (s *Server) handleWebhook(c *gin.Context) {
	source := c.Param("source")
	if source == "" {
		c.JSON(http.StatusBadRequest, gin.H{"error": "source is required"})
		return
	}

	var event WebhookEvent
	if err := c.ShouldBindJSON(&event); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": "invalid request body", "detail": err.Error()})
		return
	}

	if event.ID == "" {
		event.ID = generateEventID()
	}

	if event.Type == "" {
		c.JSON(http.StatusBadRequest, gin.H{"error": "event type is required"})
		return
	}

	if event.Timestamp.IsZero() {
		event.Timestamp = time.Now()
	}

	event.Source = source

	klog.V(2).InfoS("Processing webhook event",
		"eventId", event.ID,
		"eventType", event.Type,
		"source", source,
	)

	ctx := c.Request.Context()

	handler, ok := s.handlers[source]
	if !ok {
		resp := s.defaultHandler(ctx, &event)
		c.JSON(http.StatusOK, resp)
		return
	}

	resp, err := handler.Handle(ctx, &event)
	if err != nil {
		klog.ErrorS(err, "Webhook handler error", "eventId", event.ID, "eventType", event.Type)
		c.JSON(http.StatusInternalServerError, gin.H{
			"success": false,
			"error":   err.Error(),
		})
		return
	}

	c.JSON(http.StatusOK, resp)
}

func (s *Server) defaultHandler(ctx context.Context, event *WebhookEvent) *WebhookResponse {
	klog.V(2).InfoS("Default webhook handler", "eventId", event.ID, "eventType", event.Type)
	return &WebhookResponse{
		Success: true,
		Message: "event received",
	}
}

func (s *Server) RegisterHandler(source string, handler WebhookHandler) {
	s.handlers[source] = handler
}

func (s *Server) RegisterHandlerFunc(source string, handler HandlerFunc) {
	s.handlers[source] = handlerFuncAdapter{fn: handler}
}

type handlerFuncAdapter struct {
	fn HandlerFunc
}

func (a handlerFuncAdapter) Handle(ctx context.Context, event *WebhookEvent) (*WebhookResponse, error) {
	return a.fn(ctx, event)
}

func (s *Server) Run(ctx context.Context) error {
	addr := fmt.Sprintf(":%d", s.config.Port)

	s.server = &http.Server{
		Addr:              addr,
		Handler:           s.router,
		ReadTimeout:       s.config.ReadTimeout,
		WriteTimeout:      s.config.WriteTimeout,
		ReadHeaderTimeout: DefaultReadHeaderTimeout,
	}

	errCh := make(chan error, 1)

	go func() {
		klog.InfoS("Starting Webhook Handler server", "addr", addr)

		if err := s.server.ListenAndServe(); err != nil && err != http.ErrServerClosed {
			errCh <- err
		}
	}()

	select {
	case err := <-errCh:
		return err
	case <-ctx.Done():
		return s.Shutdown(context.Background())
	}
}

func (s *Server) Shutdown(ctx context.Context) error {
	if s.server != nil {
		klog.InfoS("Shutting down Webhook Handler server")
		return s.server.Shutdown(ctx)
	}
	return nil
}

func (s *Server) GetHandlers() map[string]WebhookHandler {
	return s.handlers
}

func generateEventID() string {
	return fmt.Sprintf("evt_%d", time.Now().UnixNano())
}

func ComputeSignature(secret string, body []byte) string {
	mac := hmac.New(sha256.New, []byte(secret))
	mac.Write(body)
	return SignaturePrefix + hex.EncodeToString(mac.Sum(nil))
}

func VerifySignature(secret, signature string, body []byte) bool {
	if len(signature) < len(SignaturePrefix) {
		return false
	}

	expectedSig := signature[len(SignaturePrefix):]

	mac := hmac.New(sha256.New, []byte(secret))
	mac.Write(body)
	computedSig := hex.EncodeToString(mac.Sum(nil))

	return hmac.Equal([]byte(expectedSig), []byte(computedSig))
}

func ParseWebhookEvent(body []byte) (*WebhookEvent, error) {
	var event WebhookEvent
	if err := json.Unmarshal(body, &event); err != nil {
		return nil, fmt.Errorf("failed to parse webhook event: %w", err)
	}
	event.RawBody = body
	return &event, nil
}

type EventQueue struct {
	events chan *WebhookEvent
}

func NewEventQueue(size int) *EventQueue {
	return &EventQueue{
		events: make(chan *WebhookEvent, size),
	}
}

func (q *EventQueue) Enqueue(event *WebhookEvent) error {
	select {
	case q.events <- event:
		return nil
	default:
		return fmt.Errorf("event queue is full")
	}
}

func (q *EventQueue) Dequeue(ctx context.Context) (*WebhookEvent, error) {
	select {
	case event := <-q.events:
		return event, nil
	case <-ctx.Done():
		return nil, ctx.Err()
	}
}

func (q *EventQueue) Len() int {
	return len(q.events)
}

type IdempotencyChecker interface {
	IsProcessed(eventID string) bool
	MarkProcessed(eventID string, ttl time.Duration) error
}

type MemoryIdempotencyChecker struct {
	processed map[string]time.Time
}

func NewMemoryIdempotencyChecker() *MemoryIdempotencyChecker {
	return &MemoryIdempotencyChecker{
		processed: make(map[string]time.Time),
	}
}

func (c *MemoryIdempotencyChecker) IsProcessed(eventID string) bool {
	t, ok := c.processed[eventID]
	if !ok {
		return false
	}
	return time.Now().Before(t)
}

func (c *MemoryIdempotencyChecker) MarkProcessed(eventID string, ttl time.Duration) error {
	c.processed[eventID] = time.Now().Add(ttl)
	return nil
}

func (c *MemoryIdempotencyChecker) Cleanup() {
	now := time.Now()
	for id, expiry := range c.processed {
		if now.After(expiry) {
			delete(c.processed, id)
		}
	}
}

