func TestConfigValidate(t *testing.T) {
	tests := []struct {
		name    string
		config  *Config
		wantErr bool
		errMsg  string
	}{
		{
			name: "valid config with signing",
			config: &Config{
				Port:           8082,
				Secret:         "test-secret",
				RequireSigning: true,
			},
			wantErr: false,
		},
		{
			name: "valid config without signing",
			config: &Config{
				Port:           8082,
				RequireSigning: false,
			},
			wantErr: false,
		},
		{
			name: "invalid port negative",
			config: &Config{
				Port:           -1,
				Secret:         "test-secret",
				RequireSigning: true,
			},
			wantErr: true,
			errMsg:  "invalid port",
		},
		{
			name: "invalid port too high",
			config: &Config{
				Port:           70000,
				Secret:         "test-secret",
				RequireSigning: true,
			},
			wantErr: true,
			errMsg:  "invalid port",
		},
		{
			name: "missing secret with signing enabled",
			config: &Config{
				Port:           8082,
				Secret:         "",
				RequireSigning: true,
			},
			wantErr: true,
			errMsg:  "secret is required when signing is enabled",
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			err := tt.config.Validate()
			if tt.wantErr {
				require.Error(t, err)
				assert.Contains(t, err.Error(), tt.errMsg)
			} else {
				require.NoError(t, err)
			}
		})
	}
}

