		processed := checker.IsProcessed("evt-002")
		assert.False(t, processed)
	})

	t.Run("cleanup", func(t *testing.T) {
		checker := NewMemoryIdempotencyChecker()
		checker.MarkProcessed("evt-003", 100*time.Millisecond)
		checker.MarkProcessed("evt-004", 1*time.Hour)

