package ratelimiter

import (
	"context"
	"fmt"
	"net/http"
	"sync"
	"time"

	"github.com/gin-gonic/gin"
	"golang.org/x/time/rate"
	"k8s.io/klog/v2"
)

const (
	DefaultPort              = 8083
	DefaultRequestsPerSecond = 100
	DefaultBurstSize         = 200
	DefaultReadTimeout       = 30 * time.Second
	DefaultWriteTimeout      = 30 * time.Second
	DefaultReadHeaderTimeout = 10 * time.Second
)

type Config struct {
	Port              int
	RequestsPerSecond float64
	BurstSize         int
	ReadTimeout       time.Duration
	WriteTimeout      time.Duration
}

type Server struct {
	router    *gin.Engine
	config    *Config
	limiter   *rate.Limiter
	limiters  sync.Map
	server    *http.Server
	startTime time.Time
}

type RateLimitConfig struct {
	RequestsPerSecond float64 `json:"requestsPerSecond"`
	BurstSize         int     `json:"burstSize"`
	Enabled           bool    `json:"enabled"`
}

type RateLimitStatus struct {
	Limit     float64 `json:"limit"`
	Remaining int     `json:"remaining"`
	Reset     int64   `json:"reset"`
}

type ClientLimiter struct {
	limiter  *rate.Limiter
	lastSeen time.Time
}

func NewConfig() *Config {
	return &Config{
		Port:              DefaultPort,
		RequestsPerSecond: DefaultRequestsPerSecond,
		BurstSize:         DefaultBurstSize,
		ReadTimeout:       DefaultReadTimeout,
		WriteTimeout:      DefaultWriteTimeout,
	}
}

func (c *Config) Validate() error {
	if c.Port <= 0 || c.Port > 65535 {
		return fmt.Errorf("invalid port: %d", c.Port)
	}
	if c.RequestsPerSecond <= 0 {
		return fmt.Errorf("requests per second must be positive")
	}
	if c.BurstSize <= 0 {
		return fmt.Errorf("burst size must be positive")
	}
	return nil
}

func NewServer(cfg *Config) *Server {
	gin.SetMode(gin.ReleaseMode)
	router := gin.New()

	limiter := rate.NewLimiter(rate.Limit(cfg.RequestsPerSecond), cfg.BurstSize)

	s := &Server{
		router:    router,
		config:    cfg,
		limiter:   limiter,
		startTime: time.Now(),
	}

	s.setupRoutes()
	return s
}

func (s *Server) setupRoutes() {
	s.router.Use(gin.Recovery())
	s.router.Use(s.loggingMiddleware())

	s.router.GET("/health", s.healthHandler)

	s.router.GET("/ratelimit/status", s.statusHandler)
	s.router.GET("/ratelimit/config", s.configHandler)
	s.router.POST("/ratelimit/check", s.checkHandler)
	s.router.POST("/ratelimit/wait", s.waitHandler)
	s.router.GET("/ratelimit/client/:clientId", s.clientStatusHandler)
	s.router.DELETE("/ratelimit/client/:clientId", s.resetClientHandler)
}

func (s *Server) loggingMiddleware() gin.HandlerFunc {
	return func(c *gin.Context) {
		start := time.Now()
		path := c.Request.URL.Path

		c.Next()

		latency := time.Since(start)
		status := c.Writer.Status()

		klog.V(2).InfoS("Rate limiter request",
			"method", c.Request.Method,
			"path", path,
			"status", status,
			"latency", latency.String(),
		)
	}
}

func (s *Server) healthHandler(c *gin.Context) {
	c.JSON(http.StatusOK, gin.H{
		"status":  "ok",
		"service": "rate-limiter",
		"uptime":  time.Since(s.startTime).String(),
	})
}

func (s *Server) statusHandler(c *gin.Context) {
	c.JSON(http.StatusOK, RateLimitStatus{
		Limit:     float64(s.limiter.Limit()),
		Remaining: s.limiter.Tokens(),
		Reset:     time.Now().Add(time.Second).Unix(),
	})
}

func (s *Server) configHandler(c *gin.Context) {
	c.JSON(http.StatusOK, RateLimitConfig{
		RequestsPerSecond: s.config.RequestsPerSecond,
		BurstSize:         s.config.BurstSize,
		Enabled:           true,
	})
}

type CheckRequest struct {
	ClientID string `json:"clientId"`
	Tokens   int    `json:"tokens"`
}

type CheckResponse struct {
	Allowed   bool   `json:"allowed"`
	Remaining int    `json:"remaining"`
	Message   string `json:"message,omitempty"`
}

func (s *Server) checkHandler(c *gin.Context) {
	var req CheckRequest
	if err := c.ShouldBindJSON(&req); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": "invalid request body", "detail": err.Error()})
		return
	}

	tokens := req.Tokens
	if tokens <= 0 {
		tokens = 1
	}

	var limiter *rate.Limiter
	if req.ClientID != "" {
		limiter = s.getOrCreateClientLimiter(req.ClientID)
	} else {
		limiter = s.limiter
	}

	allowed := limiter.AllowN(time.Now(), tokens)

	c.JSON(http.StatusOK, CheckResponse{
		Allowed:   allowed,
		Remaining: limiter.Tokens(),
		Message:   s.getStatusMessage(allowed),
	})
}

type WaitRequest struct {
	ClientID string `json:"clientId"`
	Tokens   int    `json:"tokens"`
	Timeout  string `json:"timeout"`
}

type WaitResponse struct {
	Success   bool   `json:"success"`
	Remaining int    `json:"remaining"`
	Waited    string `json:"waited"`
	Message   string `json:"message,omitempty"`
}

func (s *Server) waitHandler(c *gin.Context) {
	var req WaitRequest
	if err := c.ShouldBindJSON(&req); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": "invalid request body", "detail": err.Error()})
		return
	}

	tokens := req.Tokens
	if tokens <= 0 {
		tokens = 1
	}

	var limiter *rate.Limiter
	if req.ClientID != "" {
		limiter = s.getOrCreateClientLimiter(req.ClientID)
	} else {
		limiter = s.limiter
	}

	timeout := time.Minute
	if req.Timeout != "" {
		if parsed, err := time.ParseDuration(req.Timeout); err == nil {
			timeout = parsed
		}
	}

	start := time.Now()
	ctx, cancel := context.WithTimeout(c.Request.Context(), timeout)
	defer cancel()

	err := limiter.WaitN(ctx, tokens)
	waited := time.Since(start)

	if err != nil {
		c.JSON(http.StatusTooManyRequests, WaitResponse{
			Success: false,
			Waited:  waited.String(),
			Message: "rate limit exceeded",
		})
		return
	}

	c.JSON(http.StatusOK, WaitResponse{
		Success:   true,
		Remaining: limiter.Tokens(),
		Waited:    waited.String(),
		Message:   "request allowed",
	})
}

func (s *Server) clientStatusHandler(c *gin.Context) {
	clientID := c.Param("clientId")
	if clientID == "" {
		c.JSON(http.StatusBadRequest, gin.H{"error": "clientId is required"})
		return
	}

	value, ok := s.limiters.Load(clientID)
	if !ok {
		c.JSON(http.StatusNotFound, gin.H{"error": "client not found", "clientId": clientID})
		return
	}

	cl := value.(*ClientLimiter)
	c.JSON(http.StatusOK, RateLimitStatus{
		Limit:     float64(cl.limiter.Limit()),
		Remaining: cl.limiter.Tokens(),
		Reset:     cl.lastSeen.Add(time.Minute).Unix(),
	})
}

func (s *Server) resetClientHandler(c *gin.Context) {
	clientID := c.Param("clientId")
	if clientID == "" {
		c.JSON(http.StatusBadRequest, gin.H{"error": "clientId is required"})
		return
	}

	s.limiters.Delete(clientID)
	c.JSON(http.StatusOK, gin.H{"status": "reset", "clientId": clientID})
}

func (s *Server) getOrCreateClientLimiter(clientID string) *rate.Limiter {
	value, _ := s.limiters.LoadOrStore(clientID, &ClientLimiter{
		limiter:  rate.NewLimiter(rate.Limit(s.config.RequestsPerSecond), s.config.BurstSize),
		lastSeen: time.Now(),
	})
	cl := value.(*ClientLimiter)
	cl.lastSeen = time.Now()
	return cl.limiter
}

func (s *Server) getStatusMessage(allowed bool) string {
	if allowed {
		return "request allowed"
	}
	return "rate limit exceeded"
}

func (s *Server) Run(ctx context.Context) error {
	addr := fmt.Sprintf(":%d", s.config.Port)

	s.server = &http.Server{
		Addr:              addr,
		Handler:           s.router,
		ReadTimeout:       s.config.ReadTimeout,
		WriteTimeout:      s.config.WriteTimeout,
		ReadHeaderTimeout: DefaultReadHeaderTimeout,
	}

	errCh := make(chan error, 1)

	go func() {
		klog.InfoS("Starting Rate Limiter server", "addr", addr)
		if err := s.server.ListenAndServe(); err != nil && err != http.ErrServerClosed {
			errCh <- err
		}
	}()

	go s.cleanupIdleClients()

	select {
	case err := <-errCh:
		return err
	case <-ctx.Done():
		return s.Shutdown(context.Background())
	}
}

func (s *Server) Shutdown(ctx context.Context) error {
	if s.server != nil {
		klog.InfoS("Shutting down Rate Limiter server")
		return s.server.Shutdown(ctx)
	}
	return nil
}

func (s *Server) cleanupIdleClients() {
	ticker := time.NewTicker(5 * time.Minute)
	defer ticker.Stop()

	for range ticker.C {
		now := time.Now()
		s.limiters.Range(func(key, value interface{}) bool {
			cl := value.(*ClientLimiter)
			if now.Sub(cl.lastSeen) > 10*time.Minute {
				s.limiters.Delete(key)
			}
			return true
		})
	}
}

func (s *Server) GetClientCount() int {
	count := 0
	s.limiters.Range(func(key, value interface{}) bool {
		count++
		return true
	})
	return count
}

type RateLimitMiddleware struct {
	limiter *rate.Limiter
}

func NewRateLimitMiddleware(rps float64, burst int) *RateLimitMiddleware {
	return &RateLimitMiddleware{
		limiter: rate.NewLimiter(rate.Limit(rps), burst),
	}
}

func (m *RateLimitMiddleware) Middleware() gin.HandlerFunc {
	return func(c *gin.Context) {
		if !m.limiter.Allow() {
			c.JSON(http.StatusTooManyRequests, gin.H{
				"error":   "rate limit exceeded",
				"message": "too many requests, please try again later",
			})
			c.Abort()
			return
		}
		c.Next()
	}
}

type TokenBucket struct {
	tokens     float64
	maxTokens  float64
	refillRate float64
	lastRefill time.Time
	mu         sync.Mutex
}

func NewTokenBucket(maxTokens, refillRate float64) *TokenBucket {
	return &TokenBucket{
		tokens:     maxTokens,
		maxTokens:  maxTokens,
		refillRate: refillRate,
		lastRefill: time.Now(),
	}
}

func (tb *TokenBucket) Allow(tokens float64) bool {
	tb.mu.Lock()
	defer tb.mu.Unlock()

	tb.refill()
	if tb.tokens >= tokens {
		tb.tokens -= tokens
		return true
	}
	return false
}

func (tb *TokenBucket) refill() {
	now := time.Now()
	elapsed := now.Sub(tb.lastRefill).Seconds()
	tb.tokens = min(tb.maxTokens, tb.tokens+elapsed*tb.refillRate)
	tb.lastRefill = now
}

func (tb *TokenBucket) Tokens() float64 {
	tb.mu.Lock()
	defer tb.mu.Unlock()
	tb.refill()
	return tb.tokens
}

func (tb *TokenBucket) Reset() {
	tb.mu.Lock()
	defer tb.mu.Unlock()
	tb.tokens = tb.maxTokens
	tb.lastRefill = time.Now()
}

func min(a, b float64) float64 {
	if a < b {
		return a
	}
	return b
}

