package ratelimiter

import (
	"bytes"
	"context"
	"encoding/json"
	"net/http"
	"net/http/httptest"
	"sync"
	"testing"
	"time"

	"github.com/gin-gonic/gin"
	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
)

func init() {
	gin.SetMode(gin.TestMode)
}

func TestNewConfig(t *testing.T) {
	cfg := NewConfig()
	assert.Equal(t, DefaultPort, cfg.Port)
	assert.Equal(t, DefaultRequestsPerSecond, cfg.RequestsPerSecond)
	assert.Equal(t, DefaultBurstSize, cfg.BurstSize)
	assert.Equal(t, DefaultReadTimeout, cfg.ReadTimeout)
	assert.Equal(t, DefaultWriteTimeout, cfg.WriteTimeout)
}

func TestConfigValidate(t *testing.T) {
	tests := []struct {
		name    string
		config  *Config
		wantErr bool
		errMsg  string
	}{
		{
			name:    "valid config",
			config:  &Config{Port: 8083, RequestsPerSecond: 100, BurstSize: 200},
			wantErr: false,
		},
		{
			name:    "invalid port negative",
			config:  &Config{Port: -1, RequestsPerSecond: 100, BurstSize: 200},
			wantErr: true,
			errMsg:  "invalid port",
		},
		{
			name:    "invalid port too high",
			config:  &Config{Port: 70000, RequestsPerSecond: 100, BurstSize: 200},
			wantErr: true,
			errMsg:  "invalid port",
		},
		{
			name:    "invalid requests per second",
			config:  &Config{Port: 8083, RequestsPerSecond: -1, BurstSize: 200},
			wantErr: true,
			errMsg:  "requests per second must be positive",
		},
		{
			name:    "invalid burst size",
			config:  &Config{Port: 8083, RequestsPerSecond: 100, BurstSize: -1},
			wantErr: true,
			errMsg:  "burst size must be positive",
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			err := tt.config.Validate()
			if tt.wantErr {
				require.Error(t, err)
				assert.Contains(t, err.Error(), tt.errMsg)
			} else {
				require.NoError(t, err)
			}
		})
	}
}

func TestNewServer(t *testing.T) {
	cfg := NewConfig()
	server := NewServer(cfg)

	require.NotNil(t, server)
	assert.NotNil(t, server.router)
	assert.NotNil(t, server.config)
	assert.NotNil(t, server.limiter)
}

func TestHealthHandler(t *testing.T) {
	cfg := NewConfig()
	server := NewServer(cfg)

	w := httptest.NewRecorder()
	req, _ := http.NewRequest("GET", "/health", nil)
	server.router.ServeHTTP(w, req)

	assert.Equal(t, http.StatusOK, w.Code)

	var resp map[string]interface{}
	err := json.Unmarshal(w.Body.Bytes(), &resp)
	require.NoError(t, err)
	assert.Equal(t, "ok", resp["status"])
	assert.Equal(t, "rate-limiter", resp["service"])
}

func TestStatusHandler(t *testing.T) {
	cfg := NewConfig()
	server := NewServer(cfg)

	w := httptest.NewRecorder()
	req, _ := http.NewRequest("GET", "/ratelimit/status", nil)
	server.router.ServeHTTP(w, req)

	assert.Equal(t, http.StatusOK, w.Code)

	var resp RateLimitStatus
	err := json.Unmarshal(w.Body.Bytes(), &resp)
	require.NoError(t, err)
	assert.Equal(t, cfg.RequestsPerSecond, resp.Limit)
	assert.GreaterOrEqual(t, resp.Remaining, 0)
}

func TestConfigHandler(t *testing.T) {
	cfg := NewConfig()
	server := NewServer(cfg)

	w := httptest.NewRecorder()
	req, _ := http.NewRequest("GET", "/ratelimit/config", nil)
	server.router.ServeHTTP(w, req)

	assert.Equal(t, http.StatusOK, w.Code)

	var resp RateLimitConfig
	err := json.Unmarshal(w.Body.Bytes(), &resp)
	require.NoError(t, err)
	assert.Equal(t, cfg.RequestsPerSecond, resp.RequestsPerSecond)
	assert.Equal(t, cfg.BurstSize, resp.BurstSize)
	assert.True(t, resp.Enabled)
}

func TestCheckHandler(t *testing.T) {
	cfg := &Config{
		Port:              8083,
		RequestsPerSecond: 10,
		BurstSize:         10,
	}
	server := NewServer(cfg)

	t.Run("allowed request", func(t *testing.T) {
		reqBody := CheckRequest{Tokens: 1}
		body, _ := json.Marshal(reqBody)

		w := httptest.NewRecorder()
		req, _ := http.NewRequest("POST", "/ratelimit/check", bytes.NewReader(body))
		req.Header.Set("Content-Type", "application/json")
		server.router.ServeHTTP(w, req)

		assert.Equal(t, http.StatusOK, w.Code)

		var resp CheckResponse
		err := json.Unmarshal(w.Body.Bytes(), &resp)
		require.NoError(t, err)
		assert.True(t, resp.Allowed)
	})

	t.Run("with client ID", func(t *testing.T) {
		reqBody := CheckRequest{ClientID: "client-001", Tokens: 1}
		body, _ := json.Marshal(reqBody)

		w := httptest.NewRecorder()
		req, _ := http.NewRequest("POST", "/ratelimit/check", bytes.NewReader(body))
		req.Header.Set("Content-Type", "application/json")
		server.router.ServeHTTP(w, req)

		assert.Equal(t, http.StatusOK, w.Code)
	})

	t.Run("exceed burst", func(t *testing.T) {
		cfg := &Config{
			Port:              8083,
			RequestsPerSecond: 1,
			BurstSize:         2,
		}
		server := NewServer(cfg)

		for i := 0; i < 3; i++ {
			reqBody := CheckRequest{Tokens: 1}
			body, _ := json.Marshal(reqBody)

			w := httptest.NewRecorder()
			req, _ := http.NewRequest("POST", "/ratelimit/check", bytes.NewReader(body))
			req.Header.Set("Content-Type", "application/json")
			server.router.ServeHTTP(w, req)

			if i < 2 {
				assert.Equal(t, http.StatusOK, w.Code)
				var resp CheckResponse
				json.Unmarshal(w.Body.Bytes(), &resp)
				assert.True(t, resp.Allowed)
			}
		}
	})
}

func TestWaitHandler(t *testing.T) {
	cfg := &Config{
		Port:              8083,
		RequestsPerSecond: 100,
		BurstSize:         100,
	}
	server := NewServer(cfg)

	t.Run("successful wait", func(t *testing.T) {
		reqBody := WaitRequest{Tokens: 1, Timeout: "5s"}
		body, _ := json.Marshal(reqBody)

		w := httptest.NewRecorder()
		req, _ := http.NewRequest("POST", "/ratelimit/wait", bytes.NewReader(body))
		req.Header.Set("Content-Type", "application/json")
		server.router.ServeHTTP(w, req)

		assert.Equal(t, http.StatusOK, w.Code)

		var resp WaitResponse
		err := json.Unmarshal(w.Body.Bytes(), &resp)
		require.NoError(t, err)
		assert.True(t, resp.Success)
	})

	t.Run("with client ID", func(t *testing.T) {
		reqBody := WaitRequest{ClientID: "client-wait-001", Tokens: 1}
		body, _ := json.Marshal(reqBody)

		w := httptest.NewRecorder()
		req, _ := http.NewRequest("POST", "/ratelimit/wait", bytes.NewReader(body))
		req.Header.Set("Content-Type", "application/json")
		server.router.ServeHTTP(w, req)

		assert.Equal(t, http.StatusOK, w.Code)
	})
}

func TestClientStatusHandler(t *testing.T) {
	cfg := NewConfig()
	server := NewServer(cfg)

	clientID := "test-client-status"
	_ = server.getOrCreateClientLimiter(clientID)

	w := httptest.NewRecorder()
	req, _ := http.NewRequest("GET", "/ratelimit/client/"+clientID, nil)
	server.router.ServeHTTP(w, req)

	assert.Equal(t, http.StatusOK, w.Code)

	var resp RateLimitStatus
	err := json.Unmarshal(w.Body.Bytes(), &resp)
	require.NoError(t, err)
	assert.Equal(t, cfg.RequestsPerSecond, resp.Limit)
}

func TestClientStatusNotFound(t *testing.T) {
	cfg := NewConfig()
	server := NewServer(cfg)

	w := httptest.NewRecorder()
	req, _ := http.NewRequest("GET", "/ratelimit/client/nonexistent", nil)
	server.router.ServeHTTP(w, req)

	assert.Equal(t, http.StatusNotFound, w.Code)
}

func TestResetClientHandler(t *testing.T) {
	cfg := NewConfig()
	server := NewServer(cfg)

	clientID := "test-client-reset"
	_ = server.getOrCreateClientLimiter(clientID)

	w := httptest.NewRecorder()
	req, _ := http.NewRequest("DELETE", "/ratelimit/client/"+clientID, nil)
	server.router.ServeHTTP(w, req)

	assert.Equal(t, http.StatusOK, w.Code)

	_, ok := server.limiters.Load(clientID)
	assert.False(t, ok, "client should be deleted")
}

func TestGetClientCount(t *testing.T) {
	cfg := NewConfig()
	server := NewServer(cfg)

	assert.Equal(t, 0, server.GetClientCount())

	_ = server.getOrCreateClientLimiter("client-1")
	_ = server.getOrCreateClientLimiter("client-2")
	_ = server.getOrCreateClientLimiter("client-3")

	assert.Equal(t, 3, server.GetClientCount())
}

func TestRateLimitMiddleware(t *testing.T) {
	middleware := NewRateLimitMiddleware(10, 5)
	require.NotNil(t, middleware)

	handler := middleware.Middleware()
	require.NotNil(t, handler)
}

func TestTokenBucket(t *testing.T) {
	tb := NewTokenBucket(10, 1)

	t.Run("initial tokens", func(t *testing.T) {
		assert.Equal(t, 10.0, tb.Tokens())
	})

	t.Run("allow within limit", func(t *testing.T) {
		allowed := tb.Allow(5)
		assert.True(t, allowed)
		assert.Equal(t, 5.0, tb.Tokens())
	})

	t.Run("allow exact tokens", func(t *testing.T) {
		allowed := tb.Allow(5)
		assert.True(t, allowed)
		assert.Equal(t, 0.0, tb.Tokens())
	})

	t.Run("deny exceeding limit", func(t *testing.T) {
		allowed := tb.Allow(1)
		assert.False(t, allowed)
	})

	t.Run("reset", func(t *testing.T) {
		tb.Reset()
		assert.Equal(t, 10.0, tb.Tokens())
	})
}

func TestTokenBucketRefill(t *testing.T) {
	tb := NewTokenBucket(10, 10)

	tb.Allow(10)
	assert.Equal(t, 0.0, tb.Tokens())

	time.Sleep(100 * time.Millisecond)

	tokens := tb.Tokens()
	assert.GreaterOrEqual(t, tokens, 0.0)
	assert.LessOrEqual(t, tokens, 10.0)
}

func TestServerShutdown(t *testing.T) {
	cfg := NewConfig()
	server := NewServer(cfg)

	ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
	defer cancel()

	err := server.Shutdown(ctx)
	assert.NoError(t, err)
}

func TestConcurrentAccess(t *testing.T) {
	cfg := &Config{
		Port:              8083,
		RequestsPerSecond: 1000,
		BurstSize:         1000,
	}
	server := NewServer(cfg)

	var wg sync.WaitGroup
	for i := 0; i < 100; i++ {
		wg.Add(1)
		go func(id int) {
			defer wg.Done()
			clientID := string(rune('a' + id%26))
			_ = server.getOrCreateClientLimiter(clientID)
		}(i)
	}

	wg.Wait()
}

func TestGetStatusMessage(t *testing.T) {
	cfg := NewConfig()
	server := NewServer(cfg)

	assert.Equal(t, "request allowed", server.getStatusMessage(true))
	assert.Equal(t, "rate limit exceeded", server.getStatusMessage(false))
}

func TestClientLimiterIsolation(t *testing.T) {
	cfg := &Config{
		Port:              8083,
		RequestsPerSecond: 1,
		BurstSize:         1,
	}
	server := NewServer(cfg)

	limiter1 := server.getOrCreateClientLimiter("client-1")
	limiter2 := server.getOrCreateClientLimiter("client-2")

	assert.True(t, limiter1.Allow())
	assert.False(t, limiter1.Allow())

	assert.True(t, limiter2.Allow())
}

func TestMin(t *testing.T) {
	assert.Equal(t, 1.0, min(1.0, 2.0))
	assert.Equal(t, 2.0, min(3.0, 2.0))
	assert.Equal(t, 5.0, min(5.0, 5.0))
}

package auditlog

import (
	"context"
	"encoding/json"
	"fmt"
	"net/http"
	"sync"
	"time"

	"github.com/gin-gonic/gin"
	"k8s.io/klog/v2"
)

const (
	DefaultPort              = 8084
	DefaultBufferSize        = 1000
	DefaultReadTimeout       = 30 * time.Second
	DefaultWriteTimeout      = 30 * time.Second
	DefaultReadHeaderTimeout = 10 * time.Second
)

type Config struct {
	Port        int
	BufferSize  int
	ReadTimeout time.Duration
	WriteTimeout time.Duration
}

type AuditEntry struct {
	ID          string                 `json:"id"`
	Timestamp   time.Time              `json:"timestamp"`
	EventType   string                 `json:"eventType"`
	Actor       string                 `json:"actor"`
	Action      string                 `json:"action"`
	Resource    string                 `json:"resource"`
	ResourceID  string                 `json:"resourceId"`
	Namespace   string                 `json:"namespace,omitempty"`
	IPAddress   string                 `json:"ipAddress,omitempty"`
	UserAgent   string                 `json:"userAgent,omitempty"`
	Status      string                 `json:"status"`
	StatusCode  int                    `json:"statusCode,omitempty"`
	Duration    time.Duration          `json:"duration,omitempty"`
	Metadata    map[string]interface{} `json:"metadata,omitempty"`
	Detail      string                 `json:"detail,omitempty"`
}

type AuditFilter struct {
	EventType  string    `json:"eventType,omitempty"`
	Actor      string    `json:"actor,omitempty"`
	Resource   string    `json:"resource,omitempty"`
	Status     string    `json:"status,omitempty"`
	StartTime  time.Time `json:"startTime,omitempty"`
	EndTime    time.Time `json:"endTime,omitempty"`
}

type Server struct {
	router     *gin.Engine
	config     *Config
	buffer     chan *AuditEntry
	entries    []*AuditEntry
	mu         sync.RWMutex
	server     *http.Server
	startTime  time.Time
	exporters  []AuditExporter
}

type AuditExporter interface {
	Export(ctx context.Context, entry *AuditEntry) error
}

type AuditExporterFunc func(ctx context.Context, entry *AuditEntry) error

func (f AuditExporterFunc) Export(ctx context.Context, entry *AuditEntry) error {
	return f(ctx, entry)
}

func NewConfig() *Config {
	return &Config{
		Port:        DefaultPort,
		BufferSize:  DefaultBufferSize,
		ReadTimeout: DefaultReadTimeout,
		WriteTimeout: DefaultWriteTimeout,
	}
}

func (c *Config) Validate() error {
	if c.Port <= 0 || c.Port > 65535 {
		return fmt.Errorf("invalid port: %d", c.Port)
	}
	if c.BufferSize <= 0 {
		return fmt.Errorf("buffer size must be positive")
	}
	return nil
}

func NewServer(cfg *Config) *Server {
	gin.SetMode(gin.ReleaseMode)
	router := gin.New()

	s := &Server{
		router:    router,
		config:    cfg,
		buffer:    make(chan *AuditEntry, cfg.BufferSize),
		entries:   make([]*AuditEntry, 0),
		startTime: time.Now(),
		exporters: make([]AuditExporter, 0),
	}

	s.setupRoutes()
	go s.processBuffer()
	return s
}

func (s *Server) setupRoutes() {
	s.router.Use(gin.Recovery())
	s.router.Use(s.loggingMiddleware())

	s.router.GET("/health", s.healthHandler)

	audit := s.router.Group("/audit")
	{
		audit.POST("/log", s.logHandler)
		audit.GET("/entries", s.listEntriesHandler)
		audit.GET("/entries/:id", s.getEntryHandler)
		audit.POST("/search", s.searchHandler)
		audit.GET("/stats", s.statsHandler)
	}
}

func (s *Server) loggingMiddleware() gin.HandlerFunc {
	return func(c *gin.Context) {
		start := time.Now()
		path := c.Request.URL.Path

		c.Next()

		latency := time.Since(start)
		status := c.Writer.Status()

		klog.V(2).InfoS("Audit log request",
			"method", c.Request.Method,
			"path", path,
			"status", status,
			"latency", latency.String(),
		)
	}
}

func (s *Server) healthHandler(c *gin.Context) {
	c.JSON(http.StatusOK, gin.H{
		"status":  "ok",
		"service": "audit-logger",
		"uptime":  time.Since(s.startTime).String(),
	})
}

func (s *Server) logHandler(c *gin.Context) {
	var entry AuditEntry
	if err := c.ShouldBindJSON(&entry); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": "invalid request body", "detail": err.Error()})
		return
	}

	if entry.ID == "" {
		entry.ID = generateAuditID()
	}

	if entry.Timestamp.IsZero() {
		entry.Timestamp = time.Now()
	}

	select {
	case s.buffer <- &entry:
		c.JSON(http.StatusAccepted, gin.H{
			"status":  "accepted",
			"auditId": entry.ID,
		})
	default:
		c.JSON(http.StatusTooManyRequests, gin.H{
			"error":   "audit log buffer full",
			"message": "please retry later",
		})
	}
}

func (s *Server) listEntriesHandler(c *gin.Context) {
	limit := 100
	if l := c.Query("limit"); l != "" {
		fmt.Sscanf(l, "%d", &limit)
		if limit > 1000 {
			limit = 1000
		}
	}

	s.mu.RLock()
	entries := make([]*AuditEntry, 0, min(limit, len(s.entries)))
	for i := len(s.entries) - 1; i >= 0 && len(entries) < limit; i-- {
		entries = append(entries, s.entries[i])
	}
	s.mu.RUnlock()

	c.JSON(http.StatusOK, gin.H{
		"entries": entries,
		"count":   len(entries),
	})
}

func (s *Server) getEntryHandler(c *gin.Context) {
	id := c.Param("id")
	if id == "" {
		c.JSON(http.StatusBadRequest, gin.H{"error": "id is required"})
		return
	}

	s.mu.RLock()
	defer s.mu.RUnlock()

	for _, entry := range s.entries {
		if entry.ID == id {
			c.JSON(http.StatusOK, entry)
			return
		}
	}

	c.JSON(http.StatusNotFound, gin.H{"error": "audit entry not found", "id": id})
}

type SearchRequest struct {
	Filter AuditFilter `json:"filter"`
	Limit  int         `json:"limit"`
}

func (s *Server) searchHandler(c *gin.Context) {
	var req SearchRequest
	if err := c.ShouldBindJSON(&req); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": "invalid request body", "detail": err.Error()})
		return
	}

	limit := req.Limit
	if limit <= 0 || limit > 1000 {
		limit = 100
	}

	s.mu.RLock()
	results := make([]*AuditEntry, 0)
	for _, entry := range s.entries {
		if !s.matchesFilter(entry, &req.Filter) {
			continue
		}
		results = append(results, entry)
		if len(results) >= limit {
			break
		}
	}
	s.mu.RUnlock()

	c.JSON(http.StatusOK, gin.H{
		"entries": results,
		"count":   len(results),
	})
}

func (s *Server) matchesFilter(entry *AuditEntry, filter *AuditFilter) bool {
	if filter.EventType != "" && entry.EventType != filter.EventType {
		return false
	}
	if filter.Actor != "" && entry.Actor != filter.Actor {
		return false
	}
	if filter.Resource != "" && entry.Resource != filter.Resource {
		return false
	}
	if filter.Status != "" && entry.Status != filter.Status {
		return false
	}
	if !filter.StartTime.IsZero() && entry.Timestamp.Before(filter.StartTime) {
		return false
	}
	if !filter.EndTime.IsZero() && entry.Timestamp.After(filter.EndTime) {
		return false
	}
	return true
}

type AuditStats struct {
	TotalEntries   int64            `json:"totalEntries"`
	ByEventType    map[string]int64 `json:"byEventType"`
	ByStatus       map[string]int64 `json:"byStatus"`
	ByResource     map[string]int64 `json:"byResource"`
	BufferSize     int              `json:"bufferSize"`
	BufferCapacity int              `json:"bufferCapacity"`
}

func (s *Server) statsHandler(c *gin.Context) {
	s.mu.RLock()
	defer s.mu.RUnlock()

	stats := AuditStats{
		TotalEntries:   int64(len(s.entries)),
		ByEventType:    make(map[string]int64),
		ByStatus:       make(map[string]int64),
		ByResource:     make(map[string]int64),
		BufferSize:     len(s.buffer),
		BufferCapacity: cap(s.buffer),
	}

	for _, entry := range s.entries {
		stats.ByEventType[entry.EventType]++
		stats.ByStatus[entry.Status]++
		stats.ByResource[entry.Resource]++
	}

	c.JSON(http.StatusOK, stats)
}

func (s *Server) processBuffer() {
	for entry := range s.buffer {
		s.mu.Lock()
		s.entries = append(s.entries, entry)
		s.mu.Unlock()

		for _, exporter := range s.exporters {
			if err := exporter.Export(context.Background(), entry); err != nil {
				klog.ErrorS(err, "Failed to export audit entry", "auditId", entry.ID)
			}
		}

		klog.V(3).InfoS("Processed audit entry",
			"auditId", entry.ID,
			"eventType", entry.EventType,
			"action", entry.Action,
		)
	}
}

func (s *Server) RegisterExporter(exporter AuditExporter) {
	s.exporters = append(s.exporters, exporter)
}

func (s *Server) Log(ctx context.Context, entry *AuditEntry) error {
	if entry.ID == "" {
		entry.ID = generateAuditID()
	}
	if entry.Timestamp.IsZero() {
		entry.Timestamp = time.Now()
	}

	select {
	case s.buffer <- entry:
		return nil
	default:
		return fmt.Errorf("audit log buffer full")
	}
}

func (s *Server) Run(ctx context.Context) error {
	addr := fmt.Sprintf(":%d", s.config.Port)

	s.server = &http.Server{
		Addr:              addr,
		Handler:           s.router,
		ReadTimeout:       s.config.ReadTimeout,
		WriteTimeout:      s.config.WriteTimeout,
		ReadHeaderTimeout: DefaultReadHeaderTimeout,
	}

	errCh := make(chan error, 1)

	go func() {
		klog.InfoS("Starting Audit Logger server", "addr", addr)
		if err := s.server.ListenAndServe(); err != nil && err != http.ErrServerClosed {
			errCh <- err
		}
	}()

	select {
	case err := <-errCh:
		return err
	case <-ctx.Done():
		return s.Shutdown(context.Background())
	}
}

func (s *Server) Shutdown(ctx context.Context) error {
	if s.server != nil {
		klog.InfoS("Shutting down Audit Logger server")
		close(s.buffer)
		return s.server.Shutdown(ctx)
	}
	return nil
}

func (s *Server) GetEntries() []*AuditEntry {
	s.mu.RLock()
	defer s.mu.RUnlock()
	return s.entries
}

func (s *Server) Clear() {
	s.mu.Lock()
	defer s.mu.Unlock()
	s.entries = make([]*AuditEntry, 0)
}

func generateAuditID() string {
	return fmt.Sprintf("audit_%d", time.Now().UnixNano())
}

type AuditMiddleware struct {
	server *Server
}

func NewAuditMiddleware(server *Server) *AuditMiddleware {
	return &AuditMiddleware{server: server}
}

func (m *AuditMiddleware) Middleware() gin.HandlerFunc {
	return func(c *gin.Context) {
		start := time.Now()

		c.Next()

		duration := time.Since(start)
		status := c.Writer.Status()

		entry := &AuditEntry{
			Timestamp:  time.Now(),
			EventType:  "http.request",
			Actor:      c.GetString("user"),
			Action:     c.Request.Method,
			Resource:   c.Request.URL.Path,
			IPAddress:  c.ClientIP(),
			UserAgent:  c.GetHeader("User-Agent"),
			Status:     statusToString(status),
			StatusCode: status,
			Duration:   duration,
			Metadata: map[string]interface{}{
				"query": c.Request.URL.RawQuery,
			},
		}

		if err := m.server.Log(c.Request.Context(), entry); err != nil {
			klog.ErrorS(err, "Failed to log audit entry")
		}
	}
}

func statusToString(status int) string {
	switch {
	case status >= 200 && status < 300:
		return "success"
	case status >= 400 && status < 500:
		return "client_error"
	case status >= 500:
		return "server_error"
	default:
		return "unknown"
	}
}

type JSONFileExporter struct {
	encoder *json.Encoder
}

func NewJSONFileExporter(encoder *json.Encoder) *JSONFileExporter {
	return &JSONFileExporter{encoder: encoder}
}

func (e *JSONFileExporter) Export(ctx context.Context, entry *AuditEntry) error {
	return e.encoder.Encode(entry)
}

