func TestMatchesFilter(t *testing.T) {
	cfg := NewConfig()
	server := NewServer(cfg)

	now := time.Now()
	entry := &AuditEntry{
		EventType: "session.created",
		Actor:     "user-001",
		Resource:  "session",
		Status:    "success",
		Timestamp: now,
	}

	tests := []struct {
		name   string
		filter AuditFilter
		expect bool
	}{
		{
			name:   "no filter",
			filter: AuditFilter{},
			expect: true,
		},
		{
			name:   "matching event type",
			filter: AuditFilter{EventType: "session.created"},
			expect: true,
		},
		{
			name:   "non-matching event type",
			filter: AuditFilter{EventType: "session.deleted"},
			expect: false,
		},
		{
			name:   "matching actor",
			filter: AuditFilter{Actor: "user-001"},
			expect: true,
		},
		{
			name:   "matching status",
			filter: AuditFilter{Status: "success"},
			expect: true,
		},
		{
			name:   "time range in range",
			filter: AuditFilter{StartTime: now.Add(-1 * time.Hour), EndTime: now.Add(1 * time.Hour)},
			expect: true,
		},
		{
			name:   "time range out of range",
			filter: AuditFilter{StartTime: now.Add(2 * time.Hour)},
			expect: false,
		},
	}

	for _, tt := range tests {
