package healthagg

import (
	"context"
	"encoding/json"
	"fmt"
	"net/http"
	"sync"
	"time"

	"github.com/gin-gonic/gin"
	"k8s.io/klog/v2"
)

const (
	DefaultPort              = 8085
	DefaultCheckInterval     = 30 * time.Second
	DefaultTimeout           = 5 * time.Second
	DefaultReadTimeout       = 30 * time.Second
	DefaultWriteTimeout      = 30 * time.Second
	DefaultReadHeaderTimeout = 10 * time.Second
)

type Config struct {
	Port          int
	CheckInterval time.Duration
	Timeout       time.Duration
	ReadTimeout   time.Duration
	WriteTimeout  time.Duration
}

type ServiceHealth struct {
	Name       string            `json:"name"`
	Endpoint   string            `json:"endpoint"`
	Status     string            `json:"status"`
	LastCheck  time.Time         `json:"lastCheck"`
	LastError string            `json:"lastError,omitempty"`
	Latency    time.Duration     `json:"latency"`
	Metadata   map[string]string `json:"metadata,omitempty"`
}

type HealthStatus struct {
	Overall    string                    `json:"overall"`
	Services   map[string]*ServiceHealth `json:"services"`
	LastUpdate time.Time                 `json:"lastUpdate"`
}

type Server struct {
	router     *gin.Engine
	config     *Config
	services   map[string]*ServiceHealth
	client     *http.Client
	mu         sync.RWMutex
	server     *http.Server
	startTime  time.Time
	stopCh     chan struct{}
}

type ServiceConfig struct {
	Name     string            `json:"name"`
	Endpoint string            `json:"endpoint"`
	Metadata map[string]string `json:"metadata,omitempty"`
}

func NewConfig() *Config {
	return &Config{
		Port:          DefaultPort,
		CheckInterval: DefaultCheckInterval,
		Timeout:       DefaultTimeout,
		ReadTimeout:   DefaultReadTimeout,
		WriteTimeout:  DefaultWriteTimeout,
	}
}

func (c *Config) Validate() error {
	if c.Port <= 0 || c.Port > 65535 {
		return fmt.Errorf("invalid port: %d", c.Port)
	}
	if c.CheckInterval <= 0 {
		return fmt.Errorf("check interval must be positive")
	}
	if c.Timeout <= 0 {
		return fmt.Errorf("timeout must be positive")
	}
	return nil
}

func NewServer(cfg *Config) *Server {
	gin.SetMode(gin.ReleaseMode)
	router := gin.New()

	client := &http.Client{
		Timeout: cfg.Timeout,
	}

	s := &Server{
		router:    router,
		config:    cfg,
		services:  make(map[string]*ServiceHealth),
		client:    client,
		startTime: time.Now(),
		stopCh:    make(chan struct{}),
	}

	s.setupRoutes()
	return s
}

func (s *Server) setupRoutes() {
	s.router.Use(gin.Recovery())
	s.router.Use(s.loggingMiddleware())

	s.router.GET("/health", s.healthHandler)

	health := s.router.Group("/health")
	{
		health.GET("/aggregate", s.aggregateHandler)
		health.GET("/services", s.listServicesHandler)
		health.GET("/services/:name", s.getServiceHandler)
		health.POST("/services", s.registerServiceHandler)
		health.DELETE("/services/:name", s.deregisterServiceHandler)
		health.POST("/check", s.checkNowHandler)
	}
}

func (s *Server) loggingMiddleware() gin.HandlerFunc {
	return func(c *gin.Context) {
		start := time.Now()
		path := c.Request.URL.Path

		c.Next()

		latency := time.Since(start)
		status := c.Writer.Status()

		klog.V(2).InfoS("Health aggregator request",
			"method", c.Request.Method,
			"path", path,
			"status", status,
			"latency", latency.String(),
		)
	}
}

func (s *Server) healthHandler(c *gin.Context) {
	c.JSON(http.StatusOK, gin.H{
		"status":  "ok",
		"service": "health-aggregator",
		"uptime":  time.Since(s.startTime).String(),
	})
}

func (s *Server) aggregateHandler(c *gin.Context) {
	status := s.GetHealthStatus()
	c.JSON(http.StatusOK, status)
}

func (s *Server) listServicesHandler(c *gin.Context) {
	s.mu.RLock()
	defer s.mu.RUnlock()

	services := make([]*ServiceHealth, 0, len(s.services))
	for _, svc := range s.services {
		services = append(services, svc)
	}

	c.JSON(http.StatusOK, gin.H{
		"services": services,
		"count":    len(services),
	})
}

func (s *Server) getServiceHandler(c *gin.Context) {
	name := c.Param("name")
	if name == "" {
		c.JSON(http.StatusBadRequest, gin.H{"error": "name is required"})
		return
	}

	s.mu.RLock()
	svc, ok := s.services[name]
	s.mu.RUnlock()

	if !ok {
		c.JSON(http.StatusNotFound, gin.H{"error": "service not found", "name": name})
		return
	}

	c.JSON(http.StatusOK, svc)
}

func (s *Server) registerServiceHandler(c *gin.Context) {
	var cfg ServiceConfig
	if err := c.ShouldBindJSON(&cfg); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": "invalid request body", "detail": err.Error()})
		return
	}

	if cfg.Name == "" || cfg.Endpoint == "" {
		c.JSON(http.StatusBadRequest, gin.H{"error": "name and endpoint are required"})
		return
	}

	svc := &ServiceHealth{
		Name:     cfg.Name,
		Endpoint: cfg.Endpoint,
		Status:   "unknown",
		Metadata: cfg.Metadata,
	}

	s.mu.Lock()
	s.services[cfg.Name] = svc
	s.mu.Unlock()

	go s.checkService(cfg.Name)

	c.JSON(http.StatusCreated, gin.H{
		"status":  "registered",
		"name":    cfg.Name,
		"message": "service registered for health monitoring",
	})
}

func (s *Server) deregisterServiceHandler(c *gin.Context) {
	name := c.Param("name")
	if name == "" {
		c.JSON(http.StatusBadRequest, gin.H{"error": "name is required"})
		return
	}

	s.mu.Lock()
	_, exists := s.services[name]
	if exists {
		delete(s.services, name)
	}
	s.mu.Unlock()

	if !exists {
		c.JSON(http.StatusNotFound, gin.H{"error": "service not found", "name": name})
		return
	}

	c.JSON(http.StatusOK, gin.H{
		"status": "deregistered",
		"name":   name,
	})
}

func (s *Server) checkNowHandler(c *gin.Context) {
	go s.checkAllServices()
	c.JSON(http.StatusAccepted, gin.H{
		"status":  "accepted",
		"message": "health check initiated",
	})
}

func (s *Server) checkService(name string) {
	s.mu.RLock()
	svc, ok := s.services[name]
	if !ok {
		s.mu.RUnlock()
		return
	}
	endpoint := svc.Endpoint
	s.mu.RUnlock()

	start := time.Now()
