	c.JSON(http.StatusOK, status)
}

func (s *Server) listServicesHandler(c *gin.Context) {
	s.mu.RLock()
	defer s.mu.RUnlock()

	services := make([]*ServiceHealth, 0, len(s.services))
	for _, svc := range s.services {
		services = append(services, svc)
	}

	c.JSON(http.StatusOK, gin.H{
		"services": services,
		"count":    len(services),
	})
}

func (s *Server) getServiceHandler(c *gin.Context) {
	name := c.Param("name")
	if name == "" {
		c.JSON(http.StatusBadRequest, gin.H{"error": "name is required"})
		return
	}

	s.mu.RLock()
	svc, ok := s.services[name]
	s.mu.RUnlock()

	if !ok {
		c.JSON(http.StatusNotFound, gin.H{"error": "service not found", "name": name})
		return
	}

	c.JSON(http.StatusOK, svc)
}

func (s *Server) registerServiceHandler(c *gin.Context) {
	var cfg ServiceConfig
	if err := c.ShouldBindJSON(&cfg); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": "invalid request body", "detail": err.Error()})
		return
	}

	if cfg.Name == "" || cfg.Endpoint == "" {
		c.JSON(http.StatusBadRequest, gin.H{"error": "name and endpoint are required"})
		return
	}

	svc := &ServiceHealth{
		Name:     cfg.Name,
		Endpoint: cfg.Endpoint,
		Status:   "unknown",
		Metadata: cfg.Metadata,
	}

	s.mu.Lock()
	s.services[cfg.Name] = svc
	s.mu.Unlock()

	go s.checkService(cfg.Name)

	c.JSON(http.StatusCreated, gin.H{
		"status":  "registered",
		"name":    cfg.Name,
		"message": "service registered for health monitoring",
	})
}

func (s *Server) deregisterServiceHandler(c *gin.Context) {
	name := c.Param("name")
	if name == "" {
		c.JSON(http.StatusBadRequest, gin.H{"error": "name is required"})
		return
	}

	s.mu.Lock()
	_, exists := s.services[name]
	if exists {
		delete(s.services, name)
	}
	s.mu.Unlock()

	if !exists {
		c.JSON(http.StatusNotFound, gin.H{"error": "service not found", "name": name})
		return
	}

	c.JSON(http.StatusOK, gin.H{
		"status": "deregistered",
		"name":   name,
	})
}

func (s *Server) checkNowHandler(c *gin.Context) {
	go s.checkAllServices()
	c.JSON(http.StatusAccepted, gin.H{
		"status":  "accepted",
		"message": "health check initiated",
	})
}

func (s *Server) checkService(name string) {
	s.mu.RLock()
	svc, ok := s.services[name]
	if !ok {
		s.mu.RUnlock()
		return
	}
	endpoint := svc.Endpoint
	s.mu.RUnlock()

	start := time.Now()
	ctx, cancel := context.WithTimeout(context.Background(), s.config.Timeout)
	defer cancel()

	req, err := http.NewRequestWithContext(ctx, "GET", endpoint, nil)
	if err != nil {
		s.updateServiceHealth(name, "error", err.Error(), 0)
		return
	}

	resp, err := s.client.Do(req)
	latency := time.Since(start)

	if err != nil {
		s.updateServiceHealth(name, "error", err.Error(), latency)
		return
	}
	defer resp.Body.Close()

	status := "healthy"
	if resp.StatusCode >= 400 {
		status = "unhealthy"
	}

	s.updateServiceHealth(name, status, "", latency)
}

func (s *Server) updateServiceHealth(name, status, errMsg string, latency time.Duration) {
	s.mu.Lock()
	defer s.mu.Unlock()

	svc, ok := s.services[name]
	if !ok {
		return
	}

	svc.Status = status
	svc.LastCheck = time.Now()
	svc.LastError = errMsg
	svc.Latency = latency
}

func (s *Server) checkAllServices() {
	s.mu.RLock()
	names := make([]string, 0, len(s.services))
	for name := range s.services {
		names = append(names, name)
	}
	s.mu.RUnlock()

	var wg sync.WaitGroup
	for _, name := range names {
		wg.Add(1)
		go func(n string) {
			defer wg.Done()
			s.checkService(n)
		}(name)
	}
	wg.Wait()
}

func (s *Server) startHealthChecks() {
	ticker := time.NewTicker(s.config.CheckInterval)
	defer ticker.Stop()

	for {
		select {
		case <-ticker.C:
			s.checkAllServices()
		case <-s.stopCh:
			return
		}
	}
}

func (s *Server) GetHealthStatus() *HealthStatus {
	s.mu.RLock()
	defer s.mu.RUnlock()

	services := make(map[string]*ServiceHealth)
	for name, svc := range s.services {
		services[name] = svc
	}

	overall := "healthy"
	for _, svc := range services {
		if svc.Status == "error" || svc.Status == "unhealthy" {
			overall = "degraded"
			break
		}
	}

	if len(services) == 0 {
		overall = "unknown"
	}

	return &HealthStatus{
		Overall:    overall,
		Services:   services,
		LastUpdate: time.Now(),
	}
}

func (s *Server) Run(ctx context.Context) error {
	go s.startHealthChecks()

	addr := fmt.Sprintf(":%d", s.config.Port)

	s.server = &http.Server{
		Addr:              addr,
		Handler:           s.router,
		ReadTimeout:       s.config.ReadTimeout,
		WriteTimeout:      s.config.WriteTimeout,
		ReadHeaderTimeout: DefaultReadHeaderTimeout,
	}

	errCh := make(chan error, 1)

	go func() {
		klog.InfoS("Starting Health Aggregator server", "addr", addr)
		if err := s.server.ListenAndServe(); err != nil && err != http.ErrServerClosed {
			errCh <- err
		}
	}()

	select {
	case err := <-errCh:
		return err
	case <-ctx.Done():
		return s.Shutdown(context.Background())
	}
}

func (s *Server) Shutdown(ctx context.Context) error {
	close(s.stopCh)
	if s.server != nil {
		klog.InfoS("Shutting down Health Aggregator server")
		return s.server.Shutdown(ctx)
	}
	return nil
}

func (s *Server) RegisterService(name, endpoint string, metadata map[string]string) {
	svc := &ServiceHealth{
		Name:     name,
		Endpoint: endpoint,
		Status:   "unknown",
		Metadata: metadata,
	}

	s.mu.Lock()
	s.services[name] = svc
	s.mu.Unlock()
}

func (s *Server) DeregisterService(name string) {
	s.mu.Lock()
	delete(s.services, name)
	s.mu.Unlock()
}

func (s *Server) GetServiceHealth(name string) *ServiceHealth {
	s.mu.RLock()
	defer s.mu.RUnlock()
	return s.services[name]
}

type HealthCheckResult struct {
	ServiceName string        `json:"serviceName"`
	Status      string        `json:"status"`
	Latency     time.Duration `json:"latency"`
	Error       string        `json:"error,omitempty"`
	Timestamp   time.Time     `json:"timestamp"`
}

func CheckEndpoint(ctx context.Context, client *http.Client, endpoint string) (*HealthCheckResult, error) {
	start := time.Now()

	req, err := http.NewRequestWithContext(ctx, "GET", endpoint, nil)
	if err != nil {
		return nil, err
	}

	resp, err := client.Do(req)
	latency := time.Since(start)

	result := &HealthCheckResult{
		Latency:   latency,
		Timestamp: time.Now(),
	}

	if err != nil {
		result.Status = "error"
		result.Error = err.Error()
		return result, err
	}
	defer resp.Body.Close()

	if resp.StatusCode >= 400 {
		result.Status = "unhealthy"
	} else {
		result.Status = "healthy"
	}

	return result, nil
}

type AggregatedHealthCheck struct {
	services map[string]*ServiceHealth
	client   *http.Client
	mu       sync.RWMutex
}

func NewAggregatedHealthCheck(timeout time.Duration) *AggregatedHealthCheck {
	return &AggregatedHealthCheck{
		services: make(map[string]*ServiceHealth),
		client: &http.Client{
			Timeout: timeout,
		},
	}
}

func (a *AggregatedHealthCheck) AddService(name, endpoint string) {
	a.mu.Lock()
	defer a.mu.Unlock()
	a.services[name] = &ServiceHealth{
		Name:     name,
		Endpoint: endpoint,
		Status:   "unknown",
	}
}

func (a *AggregatedHealthCheck) RemoveService(name string) {
	a.mu.Lock()
	defer a.mu.Unlock()
	delete(a.services, name)
}

func (a *AggregatedHealthCheck) Check(ctx context.Context) map[string]*HealthCheckResult {
	a.mu.RLock()
	defer a.mu.RUnlock()

	results := make(map[string]*HealthCheckResult)
	var wg sync.WaitGroup
	var mu sync.Mutex

	for name, svc := range a.services {
		wg.Add(1)
		go func(n string, s *ServiceHealth) {
			defer wg.Done()
			result, _ := CheckEndpoint(ctx, a.client, s.Endpoint)
			mu.Lock()
			results[n] = result
			mu.Unlock()
		}(name, svc)
	}

	wg.Wait()
	return results
}

func (a *AggregatedHealthCheck) GetOverallStatus(results map[string]*HealthCheckResult) string {
	for _, result := range results {
		if result.Status == "error" || result.Status == "unhealthy" {
			return "degraded"
		}
	}
	return "healthy"
}

