package healthagg

import (
	"bytes"
	"context"
	"encoding/json"
	"net/http"
	"net/http/httptest"
	"testing"
	"time"

	"github.com/gin-gonic/gin"
	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
)

func init() {
	gin.SetMode(gin.TestMode)
}

func TestNewConfig(t *testing.T) {
	cfg := NewConfig()
	assert.Equal(t, DefaultPort, cfg.Port)
	assert.Equal(t, DefaultCheckInterval, cfg.CheckInterval)
	assert.Equal(t, DefaultTimeout, cfg.Timeout)
	assert.Equal(t, DefaultReadTimeout, cfg.ReadTimeout)
	assert.Equal(t, DefaultWriteTimeout, cfg.WriteTimeout)
}

func TestConfigValidate(t *testing.T) {
	tests := []struct {
		name    string
		config  *Config
		wantErr bool
		errMsg  string
	}{
		{
			name:    "valid config",
			config:  &Config{Port: 8085, CheckInterval: 30 * time.Second, Timeout: 5 * time.Second},
			wantErr: false,
		},
		{
			name:    "invalid port",
			config:  &Config{Port: -1, CheckInterval: 30 * time.Second, Timeout: 5 * time.Second},
			wantErr: true,
			errMsg:  "invalid port",
		},
		{
			name:    "invalid check interval",
			config:  &Config{Port: 8085, CheckInterval: -1, Timeout: 5 * time.Second},
			wantErr: true,
			errMsg:  "check interval must be positive",
		},
		{
			name:    "invalid timeout",
			config:  &Config{Port: 8085, CheckInterval: 30 * time.Second, Timeout: -1},
			wantErr: true,
			errMsg:  "timeout must be positive",
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			err := tt.config.Validate()
			if tt.wantErr {
				require.Error(t, err)
				assert.Contains(t, err.Error(), tt.errMsg)
			} else {
				require.NoError(t, err)
			}
		})
	}
}

func TestNewServer(t *testing.T) {
	cfg := NewConfig()
	server := NewServer(cfg)

	require.NotNil(t, server)
	assert.NotNil(t, server.router)
	assert.NotNil(t, server.config)
	assert.NotNil(t, server.services)
	assert.NotNil(t, server.client)
}

func TestHealthHandler(t *testing.T) {
	cfg := NewConfig()
	server := NewServer(cfg)

	w := httptest.NewRecorder()
	req, _ := http.NewRequest("GET", "/health", nil)
	server.router.ServeHTTP(w, req)

	assert.Equal(t, http.StatusOK, w.Code)

	var resp map[string]interface{}
	err := json.Unmarshal(w.Body.Bytes(), &resp)
	require.NoError(t, err)
	assert.Equal(t, "ok", resp["status"])
	assert.Equal(t, "health-aggregator", resp["service"])
}

func TestAggregateHandler(t *testing.T) {
	cfg := NewConfig()
	server := NewServer(cfg)

	server.RegisterService("test-service", "http://localhost:8080/health", nil)

	w := httptest.NewRecorder()
	req, _ := http.NewRequest("GET", "/health/aggregate", nil)
	server.router.ServeHTTP(w, req)

	assert.Equal(t, http.StatusOK, w.Code)

	var resp HealthStatus
	err := json.Unmarshal(w.Body.Bytes(), &resp)
	require.NoError(t, err)
	assert.Contains(t, []string{"healthy", "degraded", "unknown"}, resp.Overall)
}

func TestListServicesHandler(t *testing.T) {
	cfg := NewConfig()
	server := NewServer(cfg)

	server.RegisterService("service-1", "http://localhost:8080/health", nil)
	server.RegisterService("service-2", "http://localhost:8081/health", nil)

	w := httptest.NewRecorder()
	req, _ := http.NewRequest("GET", "/health/services", nil)
	server.router.ServeHTTP(w, req)

	assert.Equal(t, http.StatusOK, w.Code)

	var resp map[string]interface{}
	err := json.Unmarshal(w.Body.Bytes(), &resp)
	require.NoError(t, err)
	assert.Contains(t, resp, "services")
	assert.Contains(t, resp, "count")
}

func TestGetServiceHandler(t *testing.T) {
	cfg := NewConfig()
	server := NewServer(cfg)

	server.RegisterService("test-service", "http://localhost:8080/health", nil)

	t.Run("existing service", func(t *testing.T) {
		w := httptest.NewRecorder()
		req, _ := http.NewRequest("GET", "/health/services/test-service", nil)
		server.router.ServeHTTP(w, req)

		assert.Equal(t, http.StatusOK, w.Code)
	})

	t.Run("non-existing service", func(t *testing.T) {
		w := httptest.NewRecorder()
		req, _ := http.NewRequest("GET", "/health/services/nonexistent", nil)
		server.router.ServeHTTP(w, req)

		assert.Equal(t, http.StatusNotFound, w.Code)
	})
}

func TestRegisterServiceHandler(t *testing.T) {
	cfg := NewConfig()
	server := NewServer(cfg)

	svcConfig := ServiceConfig{
		Name:     "new-service",
		Endpoint: "http://localhost:9090/health",
	}

	body, _ := json.Marshal(svcConfig)
	w := httptest.NewRecorder()
	req, _ := http.NewRequest("POST", "/health/services", bytes.NewReader(body))
	req.Header.Set("Content-Type", "application/json")
	server.router.ServeHTTP(w, req)

	assert.Equal(t, http.StatusCreated, w.Code)

	svc := server.GetServiceHealth("new-service")
	require.NotNil(t, svc)
	assert.Equal(t, "new-service", svc.Name)
	assert.Equal(t, "http://localhost:9090/health", svc.Endpoint)
}

func TestDeregisterServiceHandler(t *testing.T) {
	cfg := NewConfig()
	server := NewServer(cfg)

	server.RegisterService("to-remove", "http://localhost:8080/health", nil)

	w := httptest.NewRecorder()
	req, _ := http.NewRequest("DELETE", "/health/services/to-remove", nil)
	server.router.ServeHTTP(w, req)

	assert.Equal(t, http.StatusOK, w.Code)

	svc := server.GetServiceHealth("to-remove")
	assert.Nil(t, svc)
}

func TestCheckNowHandler(t *testing.T) {
	cfg := NewConfig()
	server := NewServer(cfg)

	server.RegisterService("test-service", "http://localhost:8080/health", nil)

	w := httptest.NewRecorder()
	req, _ := http.NewRequest("POST", "/health/check", nil)
	server.router.ServeHTTP(w, req)

	assert.Equal(t, http.StatusAccepted, w.Code)
}

func TestGetHealthStatus(t *testing.T) {
	cfg := NewConfig()
	server := NewServer(cfg)

	server.RegisterService("service-1", "http://localhost:8080/health", nil)

	status := server.GetHealthStatus()

	require.NotNil(t, status)
	assert.Contains(t, status.Services, "service-1")
}

func TestRegisterService(t *testing.T) {
	cfg := NewConfig()
	server := NewServer(cfg)

	server.RegisterService("manual-service", "http://localhost:7070/health", map[string]string{"env": "test"})

	svc := server.GetServiceHealth("manual-service")
	require.NotNil(t, svc)
	assert.Equal(t, "manual-service", svc.Name)
	assert.Equal(t, "http://localhost:7070/health", svc.Endpoint)
	assert.Equal(t, "test", svc.Metadata["env"])
}

func TestDeregisterService(t *testing.T) {
	cfg := NewConfig()
	server := NewServer(cfg)

	server.RegisterService("to-deregister", "http://localhost:8080/health", nil)
	server.DeregisterService("to-deregister")

	svc := server.GetServiceHealth("to-deregister")
	assert.Nil(t, svc)
}

func TestAggregatedHealthCheck(t *testing.T) {
	agg := NewAggregatedHealthCheck(5 * time.Second)

	agg.AddService("service-1", "http://localhost:8080/health")
	agg.AddService("service-2", "http://localhost:8081/health")

	results := agg.Check(context.Background())

	assert.Contains(t, results, "service-1")
	assert.Contains(t, results, "service-2")
}

func TestGetOverallStatus(t *testing.T) {
	agg := NewAggregatedHealthCheck(5 * time.Second)

	tests := []struct {
		name     string
		results  map[string]*HealthCheckResult
		expected string
	}{
		{
			name: "all healthy",
			results: map[string]*HealthCheckResult{
				"svc1": {Status: "healthy"},
				"svc2": {Status: "healthy"},
			},
			expected: "healthy",
		},
		{
			name: "one unhealthy",
			results: map[string]*HealthCheckResult{
				"svc1": {Status: "healthy"},
				"svc2": {Status: "unhealthy"},
			},
			expected: "degraded",
		},
		{
			name: "one error",
			results: map[string]*HealthCheckResult{
				"svc1": {Status: "healthy"},
				"svc2": {Status: "error", Error: "connection refused"},
			},
			expected: "degraded",
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			status := agg.GetOverallStatus(tt.results)
			assert.Equal(t, tt.expected, status)
		})
	}
}

func TestHealthCheckResult(t *testing.T) {
	result := &HealthCheckResult{
		ServiceName: "test-service",
		Status:      "healthy",
		Latency:     100 * time.Millisecond,
		Timestamp:   time.Now(),
	}

	assert.Equal(t, "test-service", result.ServiceName)
	assert.Equal(t, "healthy", result.Status)
	assert.Equal(t, 100*time.Millisecond, result.Latency)
}

func TestServerShutdown(t *testing.T) {
	cfg := NewConfig()
	server := NewServer(cfg)

	ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
	defer cancel()

	err := server.Shutdown(ctx)
	assert.NoError(t, err)
}

func TestServiceHealth(t *testing.T) {
	svc := &ServiceHealth{
		Name:      "test-service",
		Endpoint:  "http://localhost:8080/health",
		Status:    "healthy",
		LastCheck: time.Now(),
		Latency:   50 * time.Millisecond,
		Metadata:  map[string]string{"env": "production"},
	}

	assert.Equal(t, "test-service", svc.Name)
	assert.Equal(t, "healthy", svc.Status)
	assert.Equal(t, 50*time.Millisecond, svc.Latency)
}

func TestHealthStatus(t *testing.T) {
	status := &HealthStatus{
		Overall: "healthy",
		Services: map[string]*ServiceHealth{
			"svc1": {Name: "svc1", Status: "healthy"},
			"svc2": {Name: "svc2", Status: "healthy"},
		},
		LastUpdate: time.Now(),
	}

	assert.Equal(t, "healthy", status.Overall)
	assert.Len(t, status.Services, 2)
}

func TestUpdateServiceHealth(t *testing.T) {
	cfg := NewConfig()
	server := NewServer(cfg)

	server.RegisterService("test", "http://localhost:8080/health", nil)
	server.updateServiceHealth("test", "healthy", "", 50*time.Millisecond)

	svc := server.GetServiceHealth("test")
	require.NotNil(t, svc)
	assert.Equal(t, "healthy", svc.Status)
	assert.Equal(t, 50*time.Millisecond, svc.Latency)
}

func TestMultipleServicesStatus(t *testing.T) {
	cfg := NewConfig()
	server := NewServer(cfg)

	server.RegisterService("healthy-svc", "http://localhost:8080/health", nil)
	server.RegisterService("unhealthy-svc", "http://localhost:8081/health", nil)

	server.updateServiceHealth("healthy-svc", "healthy", "", 10*time.Millisecond)
	server.updateServiceHealth("unhealthy-svc", "unhealthy", "connection refused", 0)

	status := server.GetHealthStatus()

	assert.Equal(t, "degraded", status.Overall)
}

package configreload

import (
	"context"
	"encoding/json"
	"fmt"
	"net/http"
	"sync"
	"time"

	"github.com/gin-gonic/gin"
	"k8s.io/klog/v2"
)

const (
	DefaultPort              = 8086
	DefaultReadTimeout       = 30 * time.Second
	DefaultWriteTimeout      = 30 * time.Second
	DefaultReadHeaderTimeout = 10 * time.Second
)

type Config struct {
	Port         int
	ReadTimeout  time.Duration
	WriteTimeout time.Duration
}

type Server struct {
	router      *gin.Engine
	config      *Config
	configStore *ConfigStore
	server      *http.Server
	startTime   time.Time
	watchers    []ConfigWatcher
	mu          sync.RWMutex
}

type ConfigWatcher interface {
	OnConfigChange(key string, value interface{})
}

type ConfigWatcherFunc func(key string, value interface{})

func (f ConfigWatcherFunc) OnConfigChange(key string, value interface{}) {
	f(key, value)
}

type ConfigStore struct {
	data      map[string]interface{}
	version   int64
	updatedAt time.Time
	mu        sync.RWMutex
}

type ConfigEntry struct {
	Key       string      `json:"key"`
	Value     interface{} `json:"value"`
	Version   int64       `json:"version"`
	UpdatedAt time.Time   `json:"updatedAt"`
}

type ReloadRequest struct {
	Keys []string `json:"keys"`
}

type ReloadResponse struct {
	Status  string   `json:"status"`
	Keys    []string `json:"keys,omitempty"`
	Version int64    `json:"version"`
	Message string   `json:"message,omitempty"`
}

func NewConfig() *Config {
	return &Config{
		Port:         DefaultPort,
		ReadTimeout:  DefaultReadTimeout,
		WriteTimeout: DefaultWriteTimeout,
	}
}

func (c *Config) Validate() error {
	if c.Port <= 0 || c.Port > 65535 {
		return fmt.Errorf("invalid port: %d", c.Port)
	}
	return nil
}

func NewConfigStore() *ConfigStore {
	return &ConfigStore{
		data:      make(map[string]interface{}),
		version:   1,
		updatedAt: time.Now(),
	}
}

func NewServer(cfg *Config) *Server {
	gin.SetMode(gin.ReleaseMode)
	router := gin.New()

	s := &Server{
		router:      router,
		config:      cfg,
		configStore: NewConfigStore(),
		startTime:   time.Now(),
		watchers:    make([]ConfigWatcher, 0),
	}

	s.setupRoutes()
	return s
}

func (s *Server) setupRoutes() {
	s.router.Use(gin.Recovery())
	s.router.Use(s.loggingMiddleware())

	s.router.GET("/health", s.healthHandler)

	config := s.router.Group("/config")
	{
		config.GET("", s.getConfigHandler)
		config.GET("/:key", s.getConfigKeyHandler)
		config.PUT("/:key", s.setConfigHandler)
		config.DELETE("/:key", s.deleteConfigHandler)
		config.POST("/reload", s.reloadHandler)
		config.POST("/batch", s.batchUpdateHandler)
		config.GET("/version", s.versionHandler)
	}
}

func (s *Server) loggingMiddleware() gin.HandlerFunc {
	return func(c *gin.Context) {
		start := time.Now()
		path := c.Request.URL.Path

		c.Next()

		latency := time.Since(start)
		status := c.Writer.Status()

		klog.V(2).InfoS("Config reload request",
			"method", c.Request.Method,
			"path", path,
			"status", status,
			"latency", latency.String(),
		)
	}
}

func (s *Server) healthHandler(c *gin.Context) {
	c.JSON(http.StatusOK, gin.H{
		"status":  "ok",
		"service": "config-reload",
		"uptime":  time.Since(s.startTime).String(),
	})
}

func (s *Server) getConfigHandler(c *gin.Context) {
	s.configStore.mu.RLock()
	defer s.configStore.mu.RUnlock()

	c.JSON(http.StatusOK, gin.H{
		"config":    s.configStore.data,
		"version":   s.configStore.version,
		"updatedAt": s.configStore.updatedAt,
	})
}

func (s *Server) getConfigKeyHandler(c *gin.Context) {
	key := c.Param("key")
	if key == "" {
		c.JSON(http.StatusBadRequest, gin.H{"error": "key is required"})
		return
	}

	s.configStore.mu.RLock()
	value, ok := s.configStore.data[key]
	s.configStore.mu.RUnlock()

	if !ok {
		c.JSON(http.StatusNotFound, gin.H{"error": "config key not found", "key": key})
		return
	}

	c.JSON(http.StatusOK, ConfigEntry{
		Key:       key,
		Value:     value,
		Version:   s.configStore.version,
		UpdatedAt: s.configStore.updatedAt,
	})
}

type SetConfigRequest struct {
	Value interface{} `json:"value"`
}

func (s *Server) setConfigHandler(c *gin.Context) {
	key := c.Param("key")
	if key == "" {
		c.JSON(http.StatusBadRequest, gin.H{"error": "key is required"})
		return
	}

	var req SetConfigRequest
	if err := c.ShouldBindJSON(&req); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": "invalid request body", "detail": err.Error()})
		return
	}

	s.configStore.mu.Lock()
	s.configStore.data[key] = req.Value
	s.configStore.version++
	s.configStore.updatedAt = time.Now()
	version := s.configStore.version
	s.configStore.mu.Unlock()

	s.notifyWatchers(key, req.Value)

	klog.V(2).InfoS("Config updated", "key", key, "version", version)

	c.JSON(http.StatusOK, ConfigEntry{
		Key:       key,
		Value:     req.Value,
		Version:   version,
		UpdatedAt: time.Now(),
	})
}

func (s *Server) deleteConfigHandler(c *gin.Context) {
	key := c.Param("key")
	if key == "" {
		c.JSON(http.StatusBadRequest, gin.H{"error": "key is required"})
		return
	}

	s.configStore.mu.Lock()
	_, ok := s.configStore.data[key]
	if ok {
		delete(s.configStore.data, key)
		s.configStore.version++
		s.configStore.updatedAt = time.Now()
	}
	version := s.configStore.version
	s.configStore.mu.Unlock()

	if !ok {
		c.JSON(http.StatusNotFound, gin.H{"error": "config key not found", "key": key})
		return
	}

	s.notifyWatchers(key, nil)

	c.JSON(http.StatusOK, gin.H{
		"status":  "deleted",
		"key":     key,
		"version": version,
	})
}

func (s *Server) reloadHandler(c *gin.Context) {
	var req ReloadRequest
	if err := c.ShouldBindJSON(&req); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": "invalid request body", "detail": err.Error()})
		return
	}

	s.configStore.mu.Lock()
	s.configStore.version++
	s.configStore.updatedAt = time.Now()
	version := s.configStore.version
	s.configStore.mu.Unlock()

	keys := req.Keys
	if len(keys) == 0 {
		s.configStore.mu.RLock()
		for k := range s.configStore.data {
			keys = append(keys, k)
		}
		s.configStore.mu.RUnlock()
	}

	for _, key := range keys {
		s.configStore.mu.RLock()
		value := s.configStore.data[key]
		s.configStore.mu.RUnlock()
		s.notifyWatchers(key, value)
	}

	klog.InfoS("Config reloaded", "keys", keys, "version", version)

	c.JSON(http.StatusOK, ReloadResponse{
		Status:  "reloaded",
		Keys:    keys,
		Version: version,
		Message: "configuration reload completed",
	})
}

type BatchUpdateRequest struct {
	Configs map[string]interface{} `json:"configs"`
}

func (s *Server) batchUpdateHandler(c *gin.Context) {
	var req BatchUpdateRequest
	if err := c.ShouldBindJSON(&req); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": "invalid request body", "detail": err.Error()})
		return
	}

	s.configStore.mu.Lock()
	for key, value := range req.Configs {
		s.configStore.data[key] = value
	}
	s.configStore.version++
	s.configStore.updatedAt = time.Now()
	version := s.configStore.version
	s.configStore.mu.Unlock()

	for key, value := range req.Configs {
		s.notifyWatchers(key, value)
	}

	c.JSON(http.StatusOK, gin.H{
		"status":    "updated",
		"count":     len(req.Configs),
		"version":   version,
		"updatedAt": time.Now(),
	})
}

func (s *Server) versionHandler(c *gin.Context) {
	s.configStore.mu.RLock()
	defer s.configStore.mu.RUnlock()

	c.JSON(http.StatusOK, gin.H{
		"version":   s.configStore.version,
		"updatedAt": s.configStore.updatedAt,
	})
}

func (s *Server) notifyWatchers(key string, value interface{}) {
	s.mu.RLock()
	watchers := make([]ConfigWatcher, len(s.watchers))
	copy(watchers, s.watchers)
	s.mu.RUnlock()

	for _, watcher := range watchers {
		go watcher.OnConfigChange(key, value)
	}
}

func (s *Server) RegisterWatcher(watcher ConfigWatcher) {
	s.mu.Lock()
	s.watchers = append(s.watchers, watcher)
	s.mu.Unlock()
}

func (s *Server) Run(ctx context.Context) error {
	addr := fmt.Sprintf(":%d", s.config.Port)

	s.server = &http.Server{
		Addr:              addr,
		Handler:           s.router,
		ReadTimeout:       s.config.ReadTimeout,
		WriteTimeout:      s.config.WriteTimeout,
		ReadHeaderTimeout: DefaultReadHeaderTimeout,
	}

	errCh := make(chan error, 1)

	go func() {
		klog.InfoS("Starting Config Reload server", "addr", addr)
		if err := s.server.ListenAndServe(); err != nil && err != http.ErrServerClosed {
			errCh <- err
		}
	}()

	select {
	case err := <-errCh:
		return err
	case <-ctx.Done():
		return s.Shutdown(context.Background())
	}
}

func (s *Server) Shutdown(ctx context.Context) error {
	if s.server != nil {
		klog.InfoS("Shutting down Config Reload server")
		return s.server.Shutdown(ctx)
	}
	return nil
}

func (s *Server) GetConfigStore() *ConfigStore {
	return s.configStore
}

func (s *ConfigStore) Get(key string) (interface{}, bool) {
	s.mu.RLock()
	defer s.mu.RUnlock()
	value, ok := s.data[key]
	return value, ok
}

func (s *ConfigStore) Set(key string, value interface{}) {
	s.mu.Lock()
	defer s.mu.Unlock()
	s.data[key] = value
	s.version++
	s.updatedAt = time.Now()
}

func (s *ConfigStore) Delete(key string) {
	s.mu.Lock()
	defer s.mu.Unlock()
	delete(s.data, key)
	s.version++
	s.updatedAt = time.Now()
}

func (s *ConfigStore) GetAll() map[string]interface{} {
	s.mu.RLock()
	defer s.mu.RUnlock()

	result := make(map[string]interface{})
	for k, v := range s.data {
		result[k] = v
	}
	return result
}

func (s *ConfigStore) GetVersion() int64 {
	s.mu.RLock()
	defer s.mu.RUnlock()
	return s.version
}

type ConfigValidator interface {
	Validate(key string, value interface{}) error
}

type ConfigValidatorFunc func(key string, value interface{}) error

func (f ConfigValidatorFunc) Validate(key string, value interface{}) error {
	return f(key, value)
}

type ValidatedConfigStore struct {
	store     *ConfigStore
	validators map[string]ConfigValidator
}

func NewValidatedConfigStore(store *ConfigStore) *ValidatedConfigStore {
	return &ValidatedConfigStore{
		store:      store,
		validators: make(map[string]ConfigValidator),
	}
}

func (s *ValidatedConfigStore) RegisterValidator(key string, validator ConfigValidator) {
	s.validators[key] = validator
}

func (s *ValidatedConfigStore) Set(key string, value interface{}) error {
	if validator, ok := s.validators[key]; ok {
		if err := validator.Validate(key, value); err != nil {
			return err
		}
	}
	s.store.Set(key, value)
	return nil
}

func (s *ValidatedConfigStore) Get(key string) (interface{}, bool) {
	return s.store.Get(key)
}

