package sessionvalidator

import (
	"context"
	"fmt"
	"net/http"
	"sync"
	"time"

	"github.com/gin-gonic/gin"
	"k8s.io/klog/v2"

	"github.com/anomalyco/agentcube/pkg/store"
)

const (
	DefaultPort              = 8087
	DefaultCacheTTL          = 5 * time.Minute
	DefaultReadTimeout       = 30 * time.Second
	DefaultWriteTimeout      = 30 * time.Second
	DefaultReadHeaderTimeout = 10 * time.Second
)

type Config struct {
	Port        int
	CacheTTL    time.Duration
	ReadTimeout time.Duration
	WriteTimeout time.Duration
}

type Server struct {
	router    *gin.Engine
	config    *Config
	store     store.Store
	cache     *SessionCache
	server    *http.Server
	startTime time.Time
}

type SessionCache struct {
	entries map[string]*CachedSession
	mu      sync.RWMutex
	ttl     time.Duration
}

type CachedSession struct {
	SessionID  string
	Valid      bool
	ExpiresAt  time.Time
	CachedAt   time.Time
	Attributes map[string]string
}

type ValidationRequest struct {
	SessionID string            `json:"sessionId"`
	Token     string            `json:"token,omitempty"`
	Headers   map[string]string `json:"headers,omitempty"`
}

type ValidationResponse struct {
	Valid      bool              `json:"valid"`
	SessionID  string            `json:"sessionId,omitempty"`
	ExpiresAt  time.Time         `json:"expiresAt,omitempty"`
	Message    string            `json:"message,omitempty"`
	Attributes map[string]string `json:"attributes,omitempty"`
}

type BatchValidationRequest struct {
	Sessions []ValidationRequest `json:"sessions"`
}

type BatchValidationResponse struct {
	Results []ValidationResponse `json:"results"`
	Total   int                  `json:"total"`
	Valid   int                  `json:"valid"`
	Invalid int                  `json:"invalid"`
}

func NewConfig() *Config {
	return &Config{
		Port:        DefaultPort,
		CacheTTL:    DefaultCacheTTL,
		ReadTimeout: DefaultReadTimeout,
		WriteTimeout: DefaultWriteTimeout,
	}
}

func (c *Config) Validate() error {
	if c.Port <= 0 || c.Port > 65535 {
		return fmt.Errorf("invalid port: %d", c.Port)
	}
	if c.CacheTTL <= 0 {
		return fmt.Errorf("cache TTL must be positive")
	}
	return nil
}

func NewSessionCache(ttl time.Duration) *SessionCache {
	return &SessionCache{
		entries: make(map[string]*CachedSession),
		ttl:     ttl,
	}
}

func (c *SessionCache) Get(sessionID string) (*CachedSession, bool) {
	c.mu.RLock()
	defer c.mu.RUnlock()

	entry, ok := c.entries[sessionID]
	if !ok {
		return nil, false
	}

	if time.Since(entry.CachedAt) > c.ttl {
		return nil, false
	}

	return entry, true
}

func (c *SessionCache) Set(sessionID string, valid bool, expiresAt time.Time, attrs map[string]string) {
	c.mu.Lock()
	defer c.mu.Unlock()

	c.entries[sessionID] = &CachedSession{
		SessionID:  sessionID,
		Valid:      valid,
		ExpiresAt:  expiresAt,
		CachedAt:   time.Now(),
		Attributes: attrs,
	}
}

func (c *SessionCache) Delete(sessionID string) {
	c.mu.Lock()
	defer c.mu.Unlock()
	delete(c.entries, sessionID)
}

func (c *SessionCache) Clear() {
	c.mu.Lock()
	defer c.mu.Unlock()
	c.entries = make(map[string]*CachedSession)
}

func (c *SessionCache) Size() int {
	c.mu.RLock()
	defer c.mu.RUnlock()
	return len(c.entries)
}

func NewServer(cfg *Config, store store.Store) *Server {
	gin.SetMode(gin.ReleaseMode)
	router := gin.New()

	s := &Server{
		router:    router,
		config:    cfg,
		store:     store,
		cache:     NewSessionCache(cfg.CacheTTL),
		startTime: time.Now(),
	}

	s.setupRoutes()
	return s
}

func (s *Server) setupRoutes() {
	s.router.Use(gin.Recovery())
	s.router.Use(s.loggingMiddleware())

	s.router.GET("/health", s.healthHandler)

	validate := s.router.Group("/validate")
	{
		validate.POST("/session", s.validateSessionHandler)
		validate.POST("/batch", s.batchValidateHandler)
		validate.GET("/cache/stats", s.cacheStatsHandler)
		validate.DELETE("/cache/:sessionId", s.invalidateCacheHandler)
		validate.DELETE("/cache", s.clearCacheHandler)
	}
}

func (s *Server) loggingMiddleware() gin.HandlerFunc {
	return func(c *gin.Context) {
		start := time.Now()
		path := c.Request.URL.Path

		c.Next()

		latency := time.Since(start)
		status := c.Writer.Status()

		klog.V(2).InfoS("Session validator request",
			"method", c.Request.Method,
			"path", path,
			"status", status,
			"latency", latency.String(),
		)
	}
}

func (s *Server) healthHandler(c *gin.Context) {
	c.JSON(http.StatusOK, gin.H{
		"status":  "ok",
		"service": "session-validator",
		"uptime":  time.Since(s.startTime).String(),
	})
}

func (s *Server) validateSessionHandler(c *gin.Context) {
	var req ValidationRequest
	if err := c.ShouldBindJSON(&req); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": "invalid request body", "detail": err.Error()})
		return
	}

	if req.SessionID == "" {
		c.JSON(http.StatusBadRequest, gin.H{"error": "sessionId is required"})
		return
	}

	if cached, ok := s.cache.Get(req.SessionID); ok {
		c.JSON(http.StatusOK, ValidationResponse{
			Valid:      cached.Valid && cached.ExpiresAt.After(time.Now()),
			SessionID:  cached.SessionID,
			ExpiresAt:  cached.ExpiresAt,
			Message:    "from cache",
			Attributes: cached.Attributes,
		})
		return
	}

	ctx := c.Request.Context()
	sandbox, err := s.store.GetSandboxBySessionID(ctx, req.SessionID)
	if err != nil {
		if err == store.ErrSessionNotFound {
			s.cache.Set(req.SessionID, false, time.Time{}, nil)
			c.JSON(http.StatusOK, ValidationResponse{
				Valid:     false,
				SessionID: req.SessionID,
				Message:   "session not found",
			})
			return
		}
		c.JSON(http.StatusInternalServerError, gin.H{"error": "validation failed", "detail": err.Error()})
		return
	}

	valid := sandbox.ExpiresAt.After(time.Now())

	attrs := make(map[string]string)
	if sandbox.Labels != nil {
		for k, v := range sandbox.Labels {
			attrs[k] = v
		}
	}

	s.cache.Set(req.SessionID, valid, sandbox.ExpiresAt, attrs)

	c.JSON(http.StatusOK, ValidationResponse{
		Valid:      valid,
		SessionID:  req.SessionID,
		ExpiresAt:  sandbox.ExpiresAt,
		Message:    "validated",
		Attributes: attrs,
	})
}

func (s *Server) batchValidateHandler(c *gin.Context) {
	var req BatchValidationRequest
	if err := c.ShouldBindJSON(&req); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": "invalid request body", "detail": err.Error()})
		return
	}

	if len(req.Sessions) == 0 {
		c.JSON(http.StatusBadRequest, gin.H{"error": "no sessions to validate"})
		return
	}

	results := make([]ValidationResponse, 0, len(req.Sessions))
	validCount := 0
	invalidCount := 0

	for _, session := range req.Sessions {
		if session.SessionID == "" {
			results = append(results, ValidationResponse{
				Valid:   false,
				Message: "empty session ID",
			})
			invalidCount++
			continue
		}

		if cached, ok := s.cache.Get(session.SessionID); ok {
			valid := cached.Valid && cached.ExpiresAt.After(time.Now())
			results = append(results, ValidationResponse{
				Valid:      valid,
				SessionID:  cached.SessionID,
				ExpiresAt:  cached.ExpiresAt,
				Message:    "from cache",
				Attributes: cached.Attributes,
			})
			if valid {
				validCount++
			} else {
				invalidCount++
			}
			continue
		}

		sandbox, err := s.store.GetSandboxBySessionID(c.Request.Context(), session.SessionID)
		if err != nil {
			s.cache.Set(session.SessionID, false, time.Time{}, nil)
			results = append(results, ValidationResponse{
				Valid:     false,
				SessionID: session.SessionID,
				Message:   "session not found",
			})
			invalidCount++
			continue
		}

		valid := sandbox.ExpiresAt.After(time.Now())
		attrs := make(map[string]string)
		if sandbox.Labels != nil {
			for k, v := range sandbox.Labels {
				attrs[k] = v
			}
		}

		s.cache.Set(session.SessionID, valid, sandbox.ExpiresAt, attrs)
		results = append(results, ValidationResponse{
			Valid:      valid,
			SessionID:  session.SessionID,
			ExpiresAt:  sandbox.ExpiresAt,
			Message:    "validated",
			Attributes: attrs,
		})

		if valid {
			validCount++
		} else {
			invalidCount++
		}
	}

	c.JSON(http.StatusOK, BatchValidationResponse{
		Results: results,
		Total:   len(req.Sessions),
		Valid:   validCount,
		Invalid: invalidCount,
	})
}

func (s *Server) cacheStatsHandler(c *gin.Context) {
	s.cache.mu.RLock()
	size := len(s.cache.entries)
	s.cache.mu.RUnlock()

	c.JSON(http.StatusOK, gin.H{
		"size":    size,
		"ttl":     s.config.CacheTTL.String(),
		"uptime":  time.Since(s.startTime).String(),
	})
}

func (s *Server) invalidateCacheHandler(c *gin.Context) {
	sessionID := c.Param("sessionId")
	if sessionID == "" {
		c.JSON(http.StatusBadRequest, gin.H{"error": "sessionId is required"})
		return
	}

	s.cache.Delete(sessionID)

	c.JSON(http.StatusOK, gin.H{
		"status":    "invalidated",
		"sessionId": sessionID,
	})
}

func (s *Server) clearCacheHandler(c *gin.Context) {
	s.cache.Clear()

	c.JSON(http.StatusOK, gin.H{
		"status":  "cleared",
		"message": "cache cleared successfully",
	})
}

func (s *Server) Run(ctx context.Context) error {
	addr := fmt.Sprintf(":%d", s.config.Port)

	s.server = &http.Server{
		Addr:              addr,
		Handler:           s.router,
		ReadTimeout:       s.config.ReadTimeout,
		WriteTimeout:      s.config.WriteTimeout,
		ReadHeaderTimeout: DefaultReadHeaderTimeout,
	}

	errCh := make(chan error, 1)

	go func() {
		klog.InfoS("Starting Session Validator server", "addr", addr)
		if err := s.server.ListenAndServe(); err != nil && err != http.ErrServerClosed {
			errCh <- err
		}
	}()

	select {
	case err := <-errCh:
		return err
	case <-ctx.Done():
		return s.Shutdown(context.Background())
	}
}

func (s *Server) Shutdown(ctx context.Context) error {
	if s.server != nil {
		klog.InfoS("Shutting down Session Validator server")
		return s.server.Shutdown(ctx)
	}
	return nil
}

func (s *Server) Validate(ctx context.Context, sessionID string) (*ValidationResponse, error) {
	if cached, ok := s.cache.Get(sessionID); ok {
		return &ValidationResponse{
			Valid:      cached.Valid && cached.ExpiresAt.After(time.Now()),
			SessionID:  cached.SessionID,
			ExpiresAt:  cached.ExpiresAt,
			Attributes: cached.Attributes,
		}, nil
	}

	sandbox, err := s.store.GetSandboxBySessionID(ctx, sessionID)
	if err != nil {
		if err == store.ErrSessionNotFound {
			s.cache.Set(sessionID, false, time.Time{}, nil)
			return &ValidationResponse{
				Valid:     false,
				SessionID: sessionID,
				Message:   "session not found",
			}, nil
		}
		return nil, err
	}

	valid := sandbox.ExpiresAt.After(time.Now())
	attrs := make(map[string]string)
	if sandbox.Labels != nil {
		for k, v := range sandbox.Labels {
			attrs[k] = v
		}
	}

	s.cache.Set(sessionID, valid, sandbox.ExpiresAt, attrs)

	return &ValidationResponse{
		Valid:      valid,
		SessionID:  sessionID,
		ExpiresAt:  sandbox.ExpiresAt,
		Attributes: attrs,
	}, nil
}

func (s *Server) Invalidate(sessionID string) {
	s.cache.Delete(sessionID)
}

func (s *Server) GetCache() *SessionCache {
	return s.cache
}

type ValidationMiddleware struct {
	server     *Server
	headerName string
}

func NewValidationMiddleware(server *Server, headerName string) *ValidationMiddleware {
	return &ValidationMiddleware{
		server:     server,
		headerName: headerName,
	}
}

func (m *ValidationMiddleware) Middleware() gin.HandlerFunc {
	return func(c *gin.Context) {
		sessionID := c.GetHeader(m.headerName)
		if sessionID == "" {
			c.JSON(http.StatusUnauthorized, gin.H{"error": "missing session header"})
			c.Abort()
			return
		}

		result, err := m.server.Validate(c.Request.Context(), sessionID)
		if err != nil {
			c.JSON(http.StatusInternalServerError, gin.H{"error": "validation failed"})
			c.Abort()
			return
		}

		if !result.Valid {
			c.JSON(http.StatusUnauthorized, gin.H{"error": "invalid or expired session"})
			c.Abort()
			return
		}

		c.Set("session_id", sessionID)
		c.Set("session_attributes", result.Attributes)
		c.Next()
	}
}

