func TestSessionCache(t *testing.T) {
	cache := NewSessionCache(5 * time.Minute)

	t.Run("set and get", func(t *testing.T) {
		cache.Set("session-1", true, time.Now().Add(1*time.Hour), map[string]string{"key": "value"})

		cached, ok := cache.Get("session-1")
		assert.True(t, ok)
		assert.True(t, cached.Valid)
		assert.Equal(t, "session-1", cached.SessionID)
		assert.Equal(t, "value", cached.Attributes["key"])
	})

	t.Run("delete", func(t *testing.T) {
		cache.Set("session-2", true, time.Now().Add(1*time.Hour), nil)
		cache.Delete("session-2")

		_, ok := cache.Get("session-2")
		assert.False(t, ok)
	})

	t.Run("size", func(t *testing.T) {
		cache.Clear()
		cache.Set("session-3", true, time.Now().Add(1*time.Hour), nil)
		assert.Equal(t, 1, cache.Size())
	})

	t.Run("clear", func(t *testing.T) {
		cache.Set("session-4", true, time.Now().Add(1*time.Hour), nil)
		cache.Clear()
		assert.Equal(t, 0, cache.Size())
	})

	t.Run("expired entry", func(t *testing.T) {
		shortCache := NewSessionCache(1 * time.Millisecond)
		shortCache.Set("session-5", true, time.Now().Add(1*time.Hour), nil)
		time.Sleep(10 * time.Millisecond)

		_, ok := shortCache.Get("session-5")
		assert.False(t, ok)
	})
}

