	server.cache.Set("to-invalidate", true, time.Now().Add(1*time.Hour), nil)

	w := httptest.NewRecorder()
	req, _ := http.NewRequest("DELETE", "/validate/cache/to-invalidate", nil)
	server.router.ServeHTTP(w, req)

	assert.Equal(t, http.StatusOK, w.Code)

	_, ok := server.cache.Get("to-invalidate")
	assert.False(t, ok)
}

func TestClearCacheHandler(t *testing.T) {
