package eventdispatch

import (
	"context"
	"fmt"
	"net/http"
	"sync"
	"time"

	"github.com/gin-gonic/gin"
	"k8s.io/klog/v2"
)

const (
	DefaultPort              = 8088
	DefaultQueueSize         = 1000
	DefaultWorkerCount       = 5
	DefaultReadTimeout       = 30 * time.Second
	DefaultWriteTimeout      = 30 * time.Second
	DefaultReadHeaderTimeout = 10 * time.Second
)

type Config struct {
	Port         int
	QueueSize    int
	WorkerCount  int
	ReadTimeout  time.Duration
	WriteTimeout time.Duration
}

type Event struct {
	ID        string                 `json:"id"`
	Type      string                 `json:"type"`
	Source    string                 `json:"source"`
	Timestamp time.Time              `json:"timestamp"`
	Payload   map[string]interface{} `json:"payload"`
}

type Subscription struct {
	ID        string
	Endpoint  string
	Events    []string
	Active    bool
	CreatedAt time.Time
}

type DispatchResult struct {
	EventID    string `json:"eventId"`
	Success    bool   `json:"success"`
	Subscriber string `json:"subscriber"`
	Error      string `json:"error,omitempty"`
}

type Server struct {
	router        *gin.Engine
	config        *Config
	queue         chan *Event
	subscriptions map[string]*Subscription
	handlers      map[string][]EventHandler
	workers       int
	server        *http.Server
	startTime     time.Time
	mu            sync.RWMutex
	wg            sync.WaitGroup
	stopCh        chan struct{}
}

type EventHandler func(ctx context.Context, event *Event) error

func NewConfig() *Config {
	return &Config{
		Port:         DefaultPort,
		QueueSize:    DefaultQueueSize,
		WorkerCount:  DefaultWorkerCount,
		ReadTimeout:  DefaultReadTimeout,
		WriteTimeout: DefaultWriteTimeout,
	}
}

func (c *Config) Validate() error {
	if c.Port <= 0 || c.Port > 65535 {
		return fmt.Errorf("invalid port: %d", c.Port)
	}
	if c.QueueSize <= 0 {
		return fmt.Errorf("queue size must be positive")
	}
	if c.WorkerCount <= 0 {
		return fmt.Errorf("worker count must be positive")
	}
	return nil
}

func NewServer(cfg *Config) *Server {
	gin.SetMode(gin.ReleaseMode)
	router := gin.New()

	s := &Server{
		router:        router,
		config:        cfg,
		queue:         make(chan *Event, cfg.QueueSize),
		subscriptions: make(map[string]*Subscription),
		handlers:      make(map[string][]EventHandler),
		workers:       cfg.WorkerCount,
		startTime:     time.Now(),
		stopCh:        make(chan struct{}),
	}

	s.setupRoutes()
	return s
}

func (s *Server) setupRoutes() {
	s.router.Use(gin.Recovery())
	s.router.Use(s.loggingMiddleware())

	s.router.GET("/health", s.healthHandler)

	events := s.router.Group("/events")
	{
		events.POST("/publish", s.publishHandler)
		events.POST("/publish/batch", s.batchPublishHandler)
		events.GET("/subscriptions", s.listSubscriptionsHandler)
		events.POST("/subscriptions", s.createSubscriptionHandler)
		events.DELETE("/subscriptions/:id", s.deleteSubscriptionHandler)
		events.GET("/stats", s.statsHandler)
	}
}

func (s *Server) loggingMiddleware() gin.HandlerFunc {
	return func(c *gin.Context) {
		start := time.Now()
		path := c.Request.URL.Path

		c.Next()

		latency := time.Since(start)
		status := c.Writer.Status()

		klog.V(2).InfoS("Event dispatch request",
			"method", c.Request.Method,
			"path", path,
			"status", status,
			"latency", latency.String(),
		)
	}
}

func (s *Server) healthHandler(c *gin.Context) {
	c.JSON(http.StatusOK, gin.H{
		"status":  "ok",
		"service": "event-dispatcher",
		"uptime":  time.Since(s.startTime).String(),
	})
}

func (s *Server) publishHandler(c *gin.Context) {
	var event Event
	if err := c.ShouldBindJSON(&event); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": "invalid request body", "detail": err.Error()})
		return
	}

	if event.ID == "" {
		event.ID = generateEventID()
	}
	if event.Timestamp.IsZero() {
		event.Timestamp = time.Now()
	}

	select {
	case s.queue <- &event:
		c.JSON(http.StatusAccepted, gin.H{
			"status":  "accepted",
			"eventId": event.ID,
		})
	default:
		c.JSON(http.StatusTooManyRequests, gin.H{
			"error":   "queue full",
			"message": "event queue is full, please retry",
		})
	}
}

type BatchPublishRequest struct {
	Events []*Event `json:"events"`
}

func (s *Server) batchPublishHandler(c *gin.Context) {
	var req BatchPublishRequest
	if err := c.ShouldBindJSON(&req); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": "invalid request body", "detail": err.Error()})
		return
	}

	if len(req.Events) == 0 {
		c.JSON(http.StatusBadRequest, gin.H{"error": "no events provided"})
		return
	}

	accepted := 0
	rejected := 0

	for _, event := range req.Events {
		if event.ID == "" {
			event.ID = generateEventID()
		}
		if event.Timestamp.IsZero() {
			event.Timestamp = time.Now()
		}

		select {
		case s.queue <- event:
			accepted++
		default:
			rejected++
		}
	}

	c.JSON(http.StatusAccepted, gin.H{
		"status":   "accepted",
		"accepted": accepted,
		"rejected": rejected,
	})
}

type CreateSubscriptionRequest struct {
	Endpoint string   `json:"endpoint"`
	Events   []string `json:"events"`
}

func (s *Server) createSubscriptionHandler(c *gin.Context) {
	var req CreateSubscriptionRequest
	if err := c.ShouldBindJSON(&req); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": "invalid request body", "detail": err.Error()})
		return
	}

	if req.Endpoint == "" {
		c.JSON(http.StatusBadRequest, gin.H{"error": "endpoint is required"})
		return
	}

	sub := &Subscription{
		ID:        generateSubscriptionID(),
		Endpoint:  req.Endpoint,
		Events:    req.Events,
		Active:    true,
		CreatedAt: time.Now(),
	}

	s.mu.Lock()
	s.subscriptions[sub.ID] = sub
	s.mu.Unlock()

	c.JSON(http.StatusCreated, gin.H{
		"status":       "created",
		"subscription": sub,
	})
}

func (s *Server) listSubscriptionsHandler(c *gin.Context) {
	s.mu.RLock()
	defer s.mu.RUnlock()

	subs := make([]*Subscription, 0, len(s.subscriptions))
	for _, sub := range s.subscriptions {
		subs = append(subs, sub)
	}

	c.JSON(http.StatusOK, gin.H{
		"subscriptions": subs,
		"count":         len(subs),
	})
}

func (s *Server) deleteSubscriptionHandler(c *gin.Context) {
	id := c.Param("id")
	if id == "" {
		c.JSON(http.StatusBadRequest, gin.H{"error": "subscription ID is required"})
		return
	}

	s.mu.Lock()
	_, exists := s.subscriptions[id]
	if exists {
		delete(s.subscriptions, id)
	}
	s.mu.Unlock()

	if !exists {
		c.JSON(http.StatusNotFound, gin.H{"error": "subscription not found", "id": id})
		return
	}

	c.JSON(http.StatusOK, gin.H{
		"status": "deleted",
		"id":     id,
	})
}

func (s *Server) statsHandler(c *gin.Context) {
	s.mu.RLock()
	subCount := len(s.subscriptions)
	s.mu.RUnlock()

	c.JSON(http.StatusOK, gin.H{
		"queueSize":    len(s.queue),
		"queueCap":     cap(s.queue),
		"subscriptions": subCount,
		"workers":      s.workers,
		"uptime":       time.Since(s.startTime).String(),
	})
}

func (s *Server) startWorkers() {
	for i := 0; i < s.workers; i++ {
		s.wg.Add(1)
		go s.worker(i)
	}
}

func (s *Server) worker(id int) {
	defer s.wg.Done()

	for {
		select {
		case event := <-s.queue:
			s.processEvent(event)
		case <-s.stopCh:
			return
		}
	}
}

func (s *Server) processEvent(event *Event) {
	ctx := context.Background()

	handlers := s.getHandlers(event.Type)
	for _, handler := range handlers {
		if err := handler(ctx, event); err != nil {
			klog.ErrorS(err, "Event handler error",
				"eventId", event.ID,
				"eventType", event.Type,
			)
		}
	}

	s.mu.RLock()
	for _, sub := range s.subscriptions {
		if sub.Active && s.matchesSubscription(event, sub) {
			go s.dispatchToSubscriber(ctx, event, sub)
		}
	}
	s.mu.RUnlock()
}

func (s *Server) dispatchToSubscriber(ctx context.Context, event *Event, sub *Subscription) {
	client := &http.Client{Timeout: 10 * time.Second}

	eventData, err := serializeEvent(event)
	if err != nil {
		klog.ErrorS(err, "Failed to serialize event", "eventId", event.ID)
		return
	}

	req, err := http.NewRequestWithContext(ctx, "POST", sub.Endpoint, nil)
	if err != nil {
		klog.ErrorS(err, "Failed to create request", "endpoint", sub.Endpoint)
		return
	}
	req.Header.Set("Content-Type", "application/json")
	req.Header.Set("X-Event-ID", event.ID)
	req.Header.Set("X-Event-Type", event.Type)

	resp, err := client.Do(req)
	if err != nil {
		klog.ErrorS(err, "Failed to dispatch event",
			"eventId", event.ID,
			"endpoint", sub.Endpoint,
		)
		return
	}
	defer resp.Body.Close()

	if resp.StatusCode >= 400 {
		klog.V(2).InfoS("Subscriber returned error",
			"eventId", event.ID,
			"subscriber", sub.ID,
			"status", resp.StatusCode,
		)
	}
}

func (s *Server) matchesSubscription(event *Event, sub *Subscription) bool {
	if len(sub.Events) == 0 {
		return true
	}

	for _, t := range sub.Events {
		if t == event.Type || t == "*" {
			return true
		}
	}
	return false
}

func (s *Server) getHandlers(eventType string) []EventHandler {
	s.mu.RLock()
	defer s.mu.RUnlock()

	return s.handlers[eventType]
}

func (s *Server) RegisterHandler(eventType string, handler EventHandler) {
	s.mu.Lock()
	defer s.mu.Unlock()

	s.handlers[eventType] = append(s.handlers[eventType], handler)
}

func (s *Server) Run(ctx context.Context) error {
	s.startWorkers()

	addr := fmt.Sprintf(":%d", s.config.Port)

	s.server = &http.Server{
		Addr:              addr,
		Handler:           s.router,
		ReadTimeout:       s.config.ReadTimeout,
		WriteTimeout:      s.config.WriteTimeout,
		ReadHeaderTimeout: DefaultReadHeaderTimeout,
	}

	errCh := make(chan error, 1)

	go func() {
		klog.InfoS("Starting Event Dispatcher server", "addr", addr)
		if err := s.server.ListenAndServe(); err != nil && err != http.ErrServerClosed {
			errCh <- err
		}
	}()

	select {
	case err := <-errCh:
		return err
	case <-ctx.Done():
		return s.Shutdown(context.Background())
	}
}

func (s *Server) Shutdown(ctx context.Context) error {
	close(s.stopCh)
	s.wg.Wait()

	if s.server != nil {
		klog.InfoS("Shutting down Event Dispatcher server")
		return s.server.Shutdown(ctx)
	}
	return nil
}

func (s *Server) Publish(event *Event) error {
	if event.ID == "" {
		event.ID = generateEventID()
	}
	if event.Timestamp.IsZero() {
		event.Timestamp = time.Now()
	}

	select {
	case s.queue <- event:
		return nil
	default:
		return fmt.Errorf("queue full")
	}
}

func (s *Server) GetQueueSize() int {
	return len(s.queue)
}

func generateEventID() string {
	return fmt.Sprintf("evt_%d", time.Now().UnixNano())
}

func generateSubscriptionID() string {
	return fmt.Sprintf("sub_%d", time.Now().UnixNano())
}

func serializeEvent(event *Event) ([]byte, error) {
	return []byte(fmt.Sprintf(`{"id":"%s","type":"%s"}`, event.ID, event.Type)), nil
}

type EventEmitter struct {
	server *Server
}

func NewEventEmitter(server *Server) *EventEmitter {
	return &EventEmitter{server: server}
}

func (e *EventEmitter) Emit(eventType string, payload map[string]interface{}) error {
	event := &Event{
		ID:        generateEventID(),
		Type:      eventType,
		Timestamp: time.Now(),
		Payload:   payload,
	}
	return e.server.Publish(event)
}

func (e *EventEmitter) EmitWithContext(ctx context.Context, eventType string, payload map[string]interface{}) error {
	return e.Emit(eventType, payload)
}

package proxypool

import (
	"context"
	"fmt"
	"net/http"
	"sync"
	"sync/atomic"
	"time"

	"github.com/gin-gonic/gin"
	"k8s.io/klog/v2"
)

const (
	DefaultPort              = 8089
	DefaultPoolSize          = 10
	DefaultHealthInterval    = 30 * time.Second
	DefaultReadTimeout       = 30 * time.Second
	DefaultWriteTimeout      = 30 * time.Second
	DefaultReadHeaderTimeout = 10 * time.Second
)

type Config struct {
	Port           int
	PoolSize       int
	HealthInterval time.Duration
	ReadTimeout    time.Duration
	WriteTimeout   time.Duration
}

type Proxy struct {
	ID        string            `json:"id"`
	Endpoint  string            `json:"endpoint"`
	Healthy   bool              `json:"healthy"`
	Requests  int64             `json:"requests"`
	Errors    int64             `json:"errors"`
	LastCheck time.Time         `json:"lastCheck"`
	Metadata  map[string]string `json:"metadata,omitempty"`
}

type Server struct {
	router   *gin.Engine
	config   *Config
	pool     map[string]*Proxy
	roundRobin uint64
	server   *http.Server
	startTime time.Time
	mu       sync.RWMutex
	client   *http.Client
	stopCh   chan struct{}
}

type RegisterProxyRequest struct {
	Endpoint string            `json:"endpoint"`
	Metadata map[string]string `json:"metadata,omitempty"`
}

type ProxyPoolStatus struct {
	Total    int   `json:"total"`
	Healthy  int   `json:"healthy"`
	Unhealthy int  `json:"unhealthy"`
}

func NewConfig() *Config {
	return &Config{
		Port:           DefaultPort,
		PoolSize:       DefaultPoolSize,
		HealthInterval: DefaultHealthInterval,
		ReadTimeout:    DefaultReadTimeout,
		WriteTimeout:   DefaultWriteTimeout,
	}
}

func (c *Config) Validate() error {
	if c.Port <= 0 || c.Port > 65535 {
		return fmt.Errorf("invalid port: %d", c.Port)
	}
	if c.PoolSize <= 0 {
		return fmt.Errorf("pool size must be positive")
	}
	return nil
}

func NewServer(cfg *Config) *Server {
	gin.SetMode(gin.ReleaseMode)
	router := gin.New()

	client := &http.Client{
		Timeout: 10 * time.Second,
	}

	s := &Server{
		router:    router,
		config:    cfg,
		pool:      make(map[string]*Proxy),
		startTime: time.Now(),
		client:    client,
		stopCh:    make(chan struct{}),
	}

	s.setupRoutes()
	return s
}

func (s *Server) setupRoutes() {
	s.router.Use(gin.Recovery())
	s.router.Use(s.loggingMiddleware())

	s.router.GET("/health", s.healthHandler)

	pool := s.router.Group("/pool")
	{
		pool.GET("", s.listProxiesHandler)
		pool.POST("", s.registerProxyHandler)
		pool.GET("/status", s.statusHandler)
		pool.GET("/next", s.getNextProxyHandler)
		pool.GET("/:id", s.getProxyHandler)
		pool.DELETE("/:id", s.removeProxyHandler)
		pool.POST("/:id/health", s.checkProxyHealthHandler)
		pool.POST("/health/all", s.checkAllHealthHandler)
	}
}

func (s *Server) loggingMiddleware() gin.HandlerFunc {
	return func(c *gin.Context) {
		start := time.Now()
		path := c.Request.URL.Path

		c.Next()

		latency := time.Since(start)
		status := c.Writer.Status()

		klog.V(2).InfoS("Proxy pool request",
			"method", c.Request.Method,
			"path", path,
			"status", status,
			"latency", latency.String(),
		)
	}
}

func (s *Server) healthHandler(c *gin.Context) {
	c.JSON(http.StatusOK, gin.H{
		"status":  "ok",
		"service": "proxy-pool",
		"uptime":  time.Since(s.startTime).String(),
	})
}

func (s *Server) listProxiesHandler(c *gin.Context) {
	s.mu.RLock()
	defer s.mu.RUnlock()

	proxies := make([]*Proxy, 0, len(s.pool))
	for _, p := range s.pool {
		proxies = append(proxies, p)
	}

	c.JSON(http.StatusOK, gin.H{
		"proxies": proxies,
		"count":   len(proxies),
	})
}

func (s *Server) registerProxyHandler(c *gin.Context) {
	var req RegisterProxyRequest
	if err := c.ShouldBindJSON(&req); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": "invalid request body", "detail": err.Error()})
		return
	}

	if req.Endpoint == "" {
		c.JSON(http.StatusBadRequest, gin.H{"error": "endpoint is required"})
		return
	}

	s.mu.Lock()
	if len(s.pool) >= s.config.PoolSize {
		s.mu.Unlock()
		c.JSON(http.StatusTooManyRequests, gin.H{"error": "pool size limit reached"})
		return
	}
	s.mu.Unlock()

	proxy := &Proxy{
		ID:        generateProxyID(),
		Endpoint:  req.Endpoint,
		Healthy:   true,
		Metadata:  req.Metadata,
		LastCheck: time.Now(),
	}

	s.mu.Lock()
	s.pool[proxy.ID] = proxy
	s.mu.Unlock()

	go s.checkHealth(proxy.ID)

	c.JSON(http.StatusCreated, gin.H{
		"status": "registered",
		"proxy":  proxy,
	})
}

func (s *Server) statusHandler(c *gin.Context) {
	s.mu.RLock()
	defer s.mu.RUnlock()

	total := len(s.pool)
	healthy := 0
	unhealthy := 0

	for _, p := range s.pool {
		if p.Healthy {
			healthy++
		} else {
			unhealthy++
		}
	}

	c.JSON(http.StatusOK, ProxyPoolStatus{
		Total:     total,
		Healthy:   healthy,
		Unhealthy: unhealthy,
	})
}

func (s *Server) getNextProxyHandler(c *gin.Context) {
	proxy := s.GetNextProxy()
	if proxy == nil {
		c.JSON(http.StatusServiceUnavailable, gin.H{
			"error":   "no available proxies",
			"message": "all proxies are unhealthy or pool is empty",
		})
		return
	}

	atomic.AddInt64(&proxy.Requests, 1)

	c.JSON(http.StatusOK, proxy)
}

func (s *Server) getProxyHandler(c *gin.Context) {
	id := c.Param("id")
	if id == "" {
		c.JSON(http.StatusBadRequest, gin.H{"error": "proxy ID is required"})
		return
	}

	s.mu.RLock()
	proxy, ok := s.pool[id]
	s.mu.RUnlock()

	if !ok {
		c.JSON(http.StatusNotFound, gin.H{"error": "proxy not found", "id": id})
		return
	}

	c.JSON(http.StatusOK, proxy)
}

func (s *Server) removeProxyHandler(c *gin.Context) {
	id := c.Param("id")
	if id == "" {
		c.JSON(http.StatusBadRequest, gin.H{"error": "proxy ID is required"})
		return
	}

	s.mu.Lock()
	_, exists := s.pool[id]
	if exists {
		delete(s.pool, id)
	}
	s.mu.Unlock()

	if !exists {
		c.JSON(http.StatusNotFound, gin.H{"error": "proxy not found", "id": id})
		return
	}

	c.JSON(http.StatusOK, gin.H{
		"status": "removed",
		"id":     id,
	})
}

func (s *Server) checkProxyHealthHandler(c *gin.Context) {
	id := c.Param("id")
	if id == "" {
		c.JSON(http.StatusBadRequest, gin.H{"error": "proxy ID is required"})
		return
	}

	s.mu.RLock()
	_, ok := s.pool[id]
	s.mu.RUnlock()

	if !ok {
		c.JSON(http.StatusNotFound, gin.H{"error": "proxy not found", "id": id})
		return
	}

	go s.checkHealth(id)

	c.JSON(http.StatusAccepted, gin.H{
		"status":  "checking",
		"proxyId": id,
	})
}

func (s *Server) checkAllHealthHandler(c *gin.Context) {
	go s.checkAllHealth()

	c.JSON(http.StatusAccepted, gin.H{
		"status":  "checking",
		"message": "health check initiated for all proxies",
	})
}

func (s *Server) checkHealth(proxyID string) {
	s.mu.RLock()
	proxy, ok := s.pool[proxyID]
	if !ok {
		s.mu.RUnlock()
		return
	}
	endpoint := proxy.Endpoint
	s.mu.RUnlock()

	ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
	defer cancel()

	req, err := http.NewRequestWithContext(ctx, "GET", endpoint+"/health", nil)
	if err != nil {
		s.updateProxyHealth(proxyID, false)
		return
	}

	resp, err := s.client.Do(req)
	if err != nil {
		s.updateProxyHealth(proxyID, false)
		return
	}
	defer resp.Body.Close()

	healthy := resp.StatusCode < 400
	s.updateProxyHealth(proxyID, healthy)
}

func (s *Server) updateProxyHealth(proxyID string, healthy bool) {
	s.mu.Lock()
	defer s.mu.Unlock()

	if proxy, ok := s.pool[proxyID]; ok {
		proxy.Healthy = healthy
		proxy.LastCheck = time.Now()
		if !healthy {
			atomic.AddInt64(&proxy.Errors, 1)
		}
	}
}

func (s *Server) checkAllHealth() {
	s.mu.RLock()
	ids := make([]string, 0, len(s.pool))
	for id := range s.pool {
		ids = append(ids, id)
	}
	s.mu.RUnlock()

	var wg sync.WaitGroup
	for _, id := range ids {
		wg.Add(1)
		go func(proxyID string) {
			defer wg.Done()
			s.checkHealth(proxyID)
		}(id)
	}
	wg.Wait()
}

func (s *Server) startHealthChecks() {
	ticker := time.NewTicker(s.config.HealthInterval)
	defer ticker.Stop()

	for {
		select {
		case <-ticker.C:
			s.checkAllHealth()
		case <-s.stopCh:
			return
		}
	}
}

func (s *Server) GetNextProxy() *Proxy {
	s.mu.RLock()
	defer s.mu.RUnlock()

	healthyProxies := make([]*Proxy, 0)
	for _, p := range s.pool {
		if p.Healthy {
			healthyProxies = append(healthyProxies, p)
		}
	}

	if len(healthyProxies) == 0 {
		return nil
	}

	idx := atomic.AddUint64(&s.roundRobin, 1) - 1
	return healthyProxies[idx%uint64(len(healthyProxies))]
}

func (s *Server) Register(endpoint string, metadata map[string]string) (*Proxy, error) {
	s.mu.Lock()
	defer s.mu.Unlock()

	if len(s.pool) >= s.config.PoolSize {
		return nil, fmt.Errorf("pool size limit reached")
	}

	proxy := &Proxy{
		ID:        generateProxyID(),
		Endpoint:  endpoint,
		Healthy:   true,
		Metadata:  metadata,
		LastCheck: time.Now(),
	}

	s.pool[proxy.ID] = proxy
	return proxy, nil
}

func (s *Server) Remove(proxyID string) error {
	s.mu.Lock()
	defer s.mu.Unlock()

	if _, ok := s.pool[proxyID]; !ok {
		return fmt.Errorf("proxy not found")
	}

	delete(s.pool, proxyID)
	return nil
}

func (s *Server) Run(ctx context.Context) error {
	go s.startHealthChecks()

	addr := fmt.Sprintf(":%d", s.config.Port)

	s.server = &http.Server{
		Addr:              addr,
		Handler:           s.router,
		ReadTimeout:       s.config.ReadTimeout,
		WriteTimeout:      s.config.WriteTimeout,
		ReadHeaderTimeout: DefaultReadHeaderTimeout,
	}

	errCh := make(chan error, 1)

	go func() {
		klog.InfoS("Starting Proxy Pool server", "addr", addr)
		if err := s.server.ListenAndServe(); err != nil && err != http.ErrServerClosed {
			errCh <- err
		}
	}()

	select {
	case err := <-errCh:
		return err
	case <-ctx.Done():
		return s.Shutdown(context.Background())
	}
}

func (s *Server) Shutdown(ctx context.Context) error {
	close(s.stopCh)
	if s.server != nil {
		klog.InfoS("Shutting down Proxy Pool server")
		return s.server.Shutdown(ctx)
	}
	return nil
}

func (s *Server) GetPool() map[string]*Proxy {
	s.mu.RLock()
	defer s.mu.RUnlock()

	result := make(map[string]*Proxy)
	for k, v := range s.pool {
		result[k] = v
	}
	return result
}

func (s *Server) GetPoolSize() int {
	s.mu.RLock()
	defer s.mu.RUnlock()
	return len(s.pool)
}

func generateProxyID() string {
	return fmt.Sprintf("proxy_%d", time.Now().UnixNano())
}

type LoadBalancer interface {
	Select(proxies []*Proxy) *Proxy
}

type RoundRobinLoadBalancer struct {
	counter uint64
}

func NewRoundRobinLoadBalancer() *RoundRobinLoadBalancer {
	return &RoundRobinLoadBalancer{}
}

func (lb *RoundRobinLoadBalancer) Select(proxies []*Proxy) *Proxy {
	if len(proxies) == 0 {
		return nil
	}

	idx := atomic.AddUint64(&lb.counter, 1) - 1
	return proxies[idx%uint64(len(proxies))]
}

type LeastConnectionsLoadBalancer struct{}

func NewLeastConnectionsLoadBalancer() *LeastConnectionsLoadBalancer {
	return &LeastConnectionsLoadBalancer{}
}

func (lb *LeastConnectionsLoadBalancer) Select(proxies []*Proxy) *Proxy {
	if len(proxies) == 0 {
		return nil
	}

	selected := proxies[0]
	for _, p := range proxies {
		if atomic.LoadInt64(&p.Requests) < atomic.LoadInt64(&selected.Requests) {
			selected = p
		}
	}
	return selected
}

